class _DebugStop(Exception):
    """Raised by Pi05Libero_UnifiedEngine._debug_op to unwind out of a compile_*
    method once the configured DEBUG_STOP_AFTER checkpoint has been emitted +
    halted, so only a partial (but valid, halted) program gets captured."""
    pass


def init_hang_prevention(ue):
    """5-step hardware clear. MUST stay identical to run_from_bin.py (see skill gotchas)."""
    halt = bytes(64)
    ue.dma_write(DMA_DEVICE_H2C, DRAM_INSTRUCTION_ADDR, halt, len(halt))
    print("[Init] HALT written to instruction DRAM base")


class Pi05Libero_UnifiedEngine(UnifiedEngine):
    _cfg = _CFG
    HIDDEN_SIZE       = _cfg["lm"]["hidden_size"]
    NUM_LAYERS        = _cfg["lm"]["num_layers"]
    NUM_HEADS         = _cfg["lm"]["num_heads"]
    NUM_KV_HEADS      = _cfg["lm"]["num_kv_heads"]
    GROUP_SIZE        = _cfg["lm"]["num_heads"] // _cfg["lm"]["num_kv_heads"]
    HEAD_DIM          = _cfg["lm"]["head_dim"]
    INTERMEDIATE_SIZE = _cfg["lm"]["intermediate_size"]
    VOCAB_SIZE        = _cfg["lm"]["vocab_size"]
    ROPE_THETA        = _cfg["lm"]["rope_theta"]
    RMS_NORM_EPS      = _cfg["lm"]["rms_norm_eps"]
    OPS               = _cfg["ops"]
    LM_QUANT          = _cfg["ops"]["lm_quant"]

    # Stepwise micro-op debug mode (see debug_stepwise.py): None = normal full
    # compile. Set to an int N (or via env var PI05_DEBUG_STOP_AFTER) to halt
    # the program immediately after the Nth _debug_op() checkpoint is emitted,
    # instead of compiling the whole thing -- lets us DMA-read that op's exact
    # HW output and assert it against a CPU reference before trusting the next
    # op. Move N up one at a time as each checkpoint passes.
    DEBUG_STOP_AFTER = None

    def __init__(self, script_dir=None, **kw):
        layout = self._cfg["dram_layout"]
        kw.setdefault("params_dram_base", int(layout["params_dram_base"], 16))
        kw.setdefault("tensor_dram_base", int(layout["tensor_dram_base"], 16))
        kw.setdefault("program_dram_base", int(layout["program_dram_base"], 16))
        super().__init__(**kw)
        self.script_dir = script_dir or os.path.dirname(os.path.abspath(__file__))
        env_stop = os.environ.get("PI05_DEBUG_STOP_AFTER")
        if env_stop is not None:
            self.DEBUG_STOP_AFTER = int(env_stop)
        self._debug_counter = 0
        self._debug_halt_info = None

    def _debug_op(self, name, dram_addr, numel, shape=None):
        """Call after emitting each op worth independently verifying. Assigns
        the next checkpoint index; if it matches DEBUG_STOP_AFTER, halts the
        program right here and raises _DebugStop so the caller's compile_*
        method unwinds early (catch it around the main body, then fall through
        to whatever finalization/subroutine-compile code normally follows)."""
        idx = self._debug_counter
        self._debug_counter += 1
        if self.DEBUG_STOP_AFTER is not None and idx == self.DEBUG_STOP_AFTER:
            self.generate_instruction_halt()
            self._debug_halt_info = {"idx": idx, "name": name, "addr": dram_addr,
                                      "numel": numel, "shape": shape}
            raise _DebugStop()
        return idx

    # ---- weights -----------------------------------------------------------
    def weight_init(self):
        """Loads all weights to params DRAM. Vision-encoder weights are owned by a
        concurrently-edited helper (_weight_init_vision); LM prefix-stack weights
        (embedder + 18 Gemma layers) are owned by _weight_init_lm_prefix below."""
        if hasattr(self, "_weight_init_vision"):
            self._weight_init_vision()
        self._weight_init_lm_prefix()
        if hasattr(self, "weight_init_action_expert"):
            self.weight_init_action_expert()

    # -- Vision encoder weights (SigLIP So400m/14, 27 layers) ----------------
    def _weight_init_vision(self):
        """Loads the SigLIP vision-encoder weights (``PaliGemma.img.*``) from
        ``weights_export/*.npy`` into params DRAM.

        Quantization policy: every matmul weight matrix (patch-embed kernel, q/k/v/out
        projections, MLP Dense_0/Dense_1, head projection) -> IF4 (q4_64) via
        ``store_quantized_weight``. LayerNorm scale/bias, every bias, and the additive
        pos-embedding stay bf16 via ``store_weight``.

        The engine's quantized matmul (``matmat_mul_core`` with ``is_B_quantized=True``)
        computes ``A @ Bᵀ`` where B is stored **N×K** (out,in) row-major (see
        ``matmat_mul_core`` docstring) — the opposite of the JAX/Flax ``.kernel`` layout
        (K,N = in,out) used by this checkpoint, so every kernel is ``.T``-transposed
        before quantization.
        """
        wdir = os.path.join(self.script_dir, "weights_export")
        with open(os.path.join(wdir, "manifest.json")) as f:
            manifest = json.load(f)

        def _load(name):
            info = manifest[name]
            return torch.from_numpy(np.load(os.path.join(wdir, info["file"])))

        def _store_q4(mat_nk):
            """mat_nk: 2-D tensor already in N×K (out,in) layout."""
            packed, _ = _mlc_quantize_q4_64(mat_nk.to(torch.bfloat16).contiguous())
            return store_quantized_weight(self, packed)

        V = self._cfg["vision"]
        H  = V["hidden_size"]        # 1152
        NH = V["num_heads"]          # 16
        D  = V["head_dim"]           # 72
        DP = 128                     # padded head_dim for flash attention (72 -> 128)
        I  = V["intermediate_size"]  # 4304
        NP = V["num_patches"]        # 256
        PS = V["patch_size"]         # 14
        # matmat_mul_core_pbi's quantized-B path asserts K % UE_VECTOR_SIZE(64) == 0 (the scale
        # DRAM stride is linear in the K blocks). Patch-embed K=588 and the MLP inner dim
        # I=4304 are NOT 64-aligned, so pad both up to the next multiple of 64 with zeros
        # (extra input features / channels contribute exactly 0, so results are unaffected).
        PATCH_K = PS * PS * 3                                              # 588 (raw patch feature count)
        PK = ((PATCH_K + UE_VECTOR_SIZE - 1) // UE_VECTOR_SIZE) * UE_VECTOR_SIZE  # 640
        IP = ((I + UE_VECTOR_SIZE - 1) // UE_VECTOR_SIZE) * UE_VECTOR_SIZE        # 4352
        self.VIS_H, self.VIS_NH, self.VIS_D, self.VIS_DP = H, NH, D, DP
        self.VIS_I, self.VIS_I_PAD, self.VIS_S, self.VIS_PATCH_K = I, IP, NP, PK
        # The flash kernel applies an internal 1/sqrt(head_dim_pad) scale; pre-scale Q by
        # sqrt(head_dim_pad/head_dim) so the *effective* scale is the correct 1/sqrt(head_dim)
        # (proven pattern, see project_vision_attn_headdim_pad_unpad memory). Folded into the
        # Q weight/bias here so no extra runtime broadcast-mul is needed.
        q_scale = math.sqrt(DP / D)

        # --- patch embedding (K padded 588 -> 640; caller must zero-pad the patchified
        # pixel input to width PK too, see _tensor_init_vision) ---
        k = _load("PaliGemma.img.embedding.kernel").reshape(-1, H)          # [588, 1152] (K,N)
        b = _load("PaliGemma.img.embedding.bias")                          # [1152]
        k_pad = torch.zeros(PK, H, dtype=k.dtype)
        k_pad[:PATCH_K] = k
        self.vis_embed_scale, self.vis_embed_data = _store_q4(k_pad.T)     # -> [1152, 640] (N,K)
        self.vis_embed_bias = store_weight(self, b)
        self.vis_pos_embed = store_weight(self, _load("PaliGemma.img.pos_embedding").reshape(NP, H))

        pfx = "PaliGemma.img.Transformer.encoderblock"
        ln0_w, ln0_b = _load(f"{pfx}.LayerNorm_0.scale"), _load(f"{pfx}.LayerNorm_0.bias")
        ln1_w, ln1_b = _load(f"{pfx}.LayerNorm_1.scale"), _load(f"{pfx}.LayerNorm_1.bias")
        q_k, q_b = _load(f"{pfx}.MultiHeadDotProductAttention_0.query.kernel"), _load(f"{pfx}.MultiHeadDotProductAttention_0.query.bias")
        k_k, k_b = _load(f"{pfx}.MultiHeadDotProductAttention_0.key.kernel"), _load(f"{pfx}.MultiHeadDotProductAttention_0.key.bias")
        v_k, v_b = _load(f"{pfx}.MultiHeadDotProductAttention_0.value.kernel"), _load(f"{pfx}.MultiHeadDotProductAttention_0.value.bias")
        o_k, o_b = _load(f"{pfx}.MultiHeadDotProductAttention_0.out.kernel"), _load(f"{pfx}.MultiHeadDotProductAttention_0.out.bias")
        d0_k, d0_b = _load(f"{pfx}.MlpBlock_0.Dense_0.kernel"), _load(f"{pfx}.MlpBlock_0.Dense_0.bias")
        d1_k, d1_b = _load(f"{pfx}.MlpBlock_0.Dense_1.kernel"), _load(f"{pfx}.MlpBlock_0.Dense_1.bias")

        self.vis_layer_addrs = []
        for l in range(27):
            la = {}
            la['ln0_w'] = store_weight(self, ln0_w[l])
            la['ln0_b'] = store_weight(self, ln0_b[l])
            la['ln1_w'] = store_weight(self, ln1_w[l])
            la['ln1_b'] = store_weight(self, ln1_b[l])

            # Q/K/V projections: pad each head's OUTPUT block D->DP (72->128) with zero
            # columns/bias, concatenated per head (col h*DP:h*DP+D real, h*DP+D:h*DP+DP
            # zero) -- the proven qwen2.5_vl_3b "qk_padded/v_padded" pattern. This keeps
            # every per-head DMA stride a full DP*bpe=256B (AXI-beat aligned) instead of
            # D*bpe=144B (NOT a multiple of the 32B AXI beat), and needs no separate
            # real-vs-padded strided copy at attention time.
            def _pad_proj(k_l, b_l, scale=1.0):
                k2d = k_l.reshape(H, NH, D)                    # (K, heads, D)
                k_pad = torch.zeros(H, NH, DP, dtype=k2d.dtype)
                k_pad[:, :, :D] = k2d * scale
                b_pad = torch.zeros(NH, DP, dtype=b_l.dtype)
                b_pad[:, :D] = b_l * scale
                return k_pad.reshape(H, NH * DP).T, b_pad.reshape(NH * DP)  # (N,K), (N)

            qk, qb = _pad_proj(q_k[l], q_b[l], q_scale)
            la['q_scale'], la['q_data'] = _store_q4(qk)
            la['q_bias'] = store_weight(self, qb)

            for short, kk_l, kb_l in (('k', k_k[l], k_b[l]), ('v', v_k[l], v_b[l])):
                kk, kb = _pad_proj(kk_l, kb_l)
                la[f'{short}_scale'], la[f'{short}_data'] = _store_q4(kk)
                la[f'{short}_bias'] = store_weight(self, kb)

            # Out projection: pad each head's INPUT block D->DP (zero rows) to match the
            # padded-concatenated attention-output layout (padded columns are exactly 0 on
            # both sides, so the extra zero rows contribute nothing either way).
            o3d = o_k[l].reshape(NH, D, H)                      # (heads, D, out)
            o_pad = torch.zeros(NH, DP, H, dtype=o3d.dtype)
            o_pad[:, :D, :] = o3d
            ok = o_pad.reshape(NH * DP, H).T                    # (N=H, K=NH*DP)
            la['o_scale'], la['o_data'] = _store_q4(ok)
            la['o_bias'] = store_weight(self, o_b[l])

            # fc1 (Dense_0): pad OUTPUT width I->IP with zero columns/bias so fc1's own
            # output buffer is directly IP-wide (real values in [0:I], exact zeros in
            # [I:IP] since both weight and bias are zero there) — no separate scatter needed.
            d0k_pad = torch.zeros(H, IP, dtype=d0_k.dtype)
            d0k_pad[:, :I] = d0_k[l]
            d0b_pad = torch.zeros(IP, dtype=d0_b.dtype)
            d0b_pad[:I] = d0_b[l]
            la['fc1_scale'], la['fc1_data'] = _store_q4(d0k_pad.T)          # [4352,1152] (N,K)
            la['fc1_bias'] = store_weight(self, d0b_pad)

            # fc2 (Dense_1): pad INPUT (K) I->IP with zero rows (fc1's padded zero columns
            # contribute exactly 0 through these zero weight rows).
            d1k_pad = torch.zeros(IP, H, dtype=d1_k.dtype)
            d1k_pad[:I] = d1_k[l]
            la['fc2_scale'], la['fc2_data'] = _store_q4(d1k_pad.T)          # [1152,4352] (N,K)
            la['fc2_bias'] = store_weight(self, d1_b[l])

            self.vis_layer_addrs.append(la)

        self.vis_encoder_norm_w = store_weight(self, _load("PaliGemma.img.Transformer.encoder_norm.scale"))
        self.vis_encoder_norm_b = store_weight(self, _load("PaliGemma.img.Transformer.encoder_norm.bias"))

        hk = _load("PaliGemma.img.head.kernel")   # [1152, 2048] (K,N)
        hb = _load("PaliGemma.img.head.bias")
        self.VIS_HEAD_OUT = hk.shape[1]
        self.vis_head_scale, self.vis_head_data = _store_q4(hk.T)          # [2048,1152] (N,K)
        self.vis_head_bias = store_weight(self, hb)

        print(f"_weight_init_vision done; params DRAM usage: {self.get_params_dram_usage()} bytes")

    # -- LM prefix stack weights (Gemma-2B: embedder + 18 layers) ------------
    def _npy(self, name):
        """Load one exported weight array (float32) from weights_export/<name>.npy."""
        path = os.path.join(self.script_dir, "weights_export", f"{name}.npy")
        return torch.from_numpy(np.load(path).astype(np.float32))

    def _quant_store(self, w2d):
        """w2d: (out, in) float32 -> quantize_q4_64 -> store_quantized_weight. in-dim must be %64==0."""
        w2d = w2d.to(torch.bfloat16).contiguous()
        packed, _ = _mlc_quantize_q4_64(w2d)
        return store_quantized_weight(self, packed)

    def _weight_init_lm_prefix(self):
        """Loads the Gemma-2B prefix LM stack: token embedder (host-side gather table,
        kept resident as bf16 for use at compile_prefix time) + per-layer RMSNorm
        (bf16, unquantized) + attn/mlp matmul weights (IF4 q4_64, per quant policy)."""
        H, D, I = self.HIDDEN_SIZE, self.HEAD_DIM, self.INTERMEDIATE_SIZE
        NH, NKV = self.NUM_HEADS, self.NUM_KV_HEADS

        # Embedder: kept as a host-resident bf16 lookup table (gather, not a matmul) —
        # rows are indexed directly at compile_prefix() time, no DRAM matmul weight needed.
        self.embedding_table = self._npy("PaliGemma.llm.embedder.input_embedding").to(torch.bfloat16)

        q_all = self._npy("PaliGemma.llm.layers.attn.q_einsum.w")          # (18, 8, 2048, 256)
        kv_all = self._npy("PaliGemma.llm.layers.attn.kv_einsum.w")        # (18, 2, 1, 2048, 256)
        o_all = self._npy("PaliGemma.llm.layers.attn.attn_vec_einsum.w")   # (18, 8, 256, 2048)
        ln1_all = self._npy("PaliGemma.llm.layers.pre_attention_norm.scale")  # (18, 2048)
        ln2_all = self._npy("PaliGemma.llm.layers.pre_ffw_norm.scale")        # (18, 2048)
        gate_up_all = self._npy("PaliGemma.llm.layers.mlp.gating_einsum")     # (18, 2, 2048, 16384)
        down_all = self._npy("PaliGemma.llm.layers.mlp.linear")               # (18, 16384, 2048)

        self.lm_layer_addrs = []
        for l in range(self.NUM_LAYERS):
            la = {}
            # rms_norm_core multiplies by GAMMA directly, no implicit +1 (confirmed
            # by reading rms_norm_core's eltwise_mul_core call in user_dma_core.py --
            # same gotcha already handled correctly for the action-expert's plain
            # AdaRMSNorm via AE_ONES_DRAM). Gemma checkpoints store this weight as a
            # DELTA from 1 (pi05_torch_ref.rms_norm applies `normed * (1.0 + scale)`),
            # so the raw checkpoint value must be pre-offset by +1 here to match --
            # this was a real bug: layer0's ln1 SNR was -3.17dB with the raw value.
            la["ln1"] = store_weight(self, ln1_all[l] + 1.0)
            la["ln2"] = store_weight(self, ln2_all[l] + 1.0)

            # q_einsum[l]: (heads, d_in=2048, head_dim=256) each head is (in,out) -> transpose
            # to (out,in) per head, stack heads along N (out) axis -> (heads*head_dim, d_in).
            q_heads = [q_all[l, h].transpose(0, 1) for h in range(NH)]       # each (256, 2048)
            q_2d = torch.cat(q_heads, dim=0)                                  # (2048, 2048) = (N,K)
            la["q_scale"], la["q_data"] = self._quant_store(q_2d)

            k_2d = kv_all[l, 0, 0].transpose(0, 1)   # (head_dim, d_in) = (256, 2048)
            v_2d = kv_all[l, 1, 0].transpose(0, 1)
            la["k_scale"], la["k_data"] = self._quant_store(k_2d)
            la["v_scale"], la["v_data"] = self._quant_store(v_2d)

            # attn_vec_einsum[l]: (heads, head_dim, d_out) -> merge (heads,head_dim) as
            # the K (in) axis, matching the (seq, heads*head_dim) attn-output layout,
            # transpose to (out, in).
            o_2d = o_all[l].reshape(NH * D, H).transpose(0, 1)   # (2048, 2048) = (N=d_out, K=heads*hd)
            la["o_scale"], la["o_data"] = self._quant_store(o_2d)

            # Gated MLP, split gate/up/down into two FF_HALF=8192-wide halves each --
            # NOT for correctness (gate/up's own N=16384 already fits matmat_mul_core_pbi
            # fine) but so down_proj's K=16384 input is available as two ALREADY-
            # SEPARATE, naturally-contiguous FF_HALF buffers from the moment they're
            # written, with no strided/gather DMA extraction step needed afterward.
            # matmat_mul_core_pbi asserts K*16 <= URAM_NEAR_FULL_ELEMENTS; K=16384
            # fails that (16384*16=262144 > 262080) so down_proj genuinely cannot run
            # as one full-K matmul (confirmed via the assertion firing when tried).
            # The old fix materialized the two K-halves via _dram_split_copy (a
            # strided per-row column-slice DMA) AFTER computing gate*up at full width
            # -- that strided copy was the confirmed hang trigger (debug_stepwise_
            # prefix.py bisection: clean through layer0_mlp_gate_up, hangs at
            # layer0_mlp_split_copy). This mirrors parakeet_test.py's proven FF_HALF
            # K-split pattern instead: split gate/up into two N=FF_HALF matmuls FIRST
            # (each writes its own naturally-separate buffer), multiply each half
            # independently, then down-project each half (K=FF_HALF, safely under the
            # URAM cap) and sum the two partial results -- no strided DMA anywhere.
            gate_2d = gate_up_all[l, 0].transpose(0, 1)   # (16384,2048) = (N,K)
            up_2d = gate_up_all[l, 1].transpose(0, 1)
            down_2d = down_all[l].transpose(0, 1)         # (2048,16384) = (N,K)
            FF_HALF = gate_2d.shape[0] // 2
            la["gate_lo_scale"], la["gate_lo_data"] = self._quant_store(gate_2d[:FF_HALF].contiguous())
            la["gate_hi_scale"], la["gate_hi_data"] = self._quant_store(gate_2d[FF_HALF:].contiguous())
            la["up_lo_scale"], la["up_lo_data"] = self._quant_store(up_2d[:FF_HALF].contiguous())
            la["up_hi_scale"], la["up_hi_data"] = self._quant_store(up_2d[FF_HALF:].contiguous())
            la["down_lo_scale"], la["down_lo_data"] = self._quant_store(down_2d[:, :FF_HALF].contiguous())
            la["down_hi_scale"], la["down_hi_data"] = self._quant_store(down_2d[:, FF_HALF:].contiguous())

            self.lm_layer_addrs.append(la)
        print(f"_weight_init_lm_prefix: {self.NUM_LAYERS} layers loaded")

    # ---- tensors -----------------------------------------------------------
    def tensor_init(self, max_seq_len=512):
        """Allocate activation/KV buffers. Addresses chosen by allocate_tensor_dram.
        NOTE: every buffer's innermost dim must be a multiple of 64 (pad if not)."""
        bpe = 2
        S, H, I, D = max_seq_len, self.HIDDEN_SIZE, self.INTERMEDIATE_SIZE, self.HEAD_DIM
        KV = self.NUM_KV_HEADS * D
        self.KV_HEAD_STRIDE = S * D * bpe
        self.KV_LAYER_STRIDE = self.NUM_KV_HEADS * self.KV_HEAD_STRIDE
        kv_total = self.NUM_LAYERS * self.KV_LAYER_STRIDE
        self.LAYER0_K_DRAM = self.allocate_tensor_dram(kv_total)
        self.LAYER0_V_DRAM = self.allocate_tensor_dram(kv_total)
        self.LAYER0_INPUT_DRAM    = self.allocate_tensor_dram(S * H * bpe)
        self.LAYER0_PRE_NORM_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.LAYER0_Q_DRAM        = self.allocate_tensor_dram(S * H * bpe)
        self.LAYER0_K_PROJ_DRAM   = self.allocate_tensor_dram(S * KV * bpe)
        self.LAYER0_V_PROJ_DRAM   = self.allocate_tensor_dram(S * KV * bpe)
        self.LAYER0_Q_PERM_DRAM   = self.allocate_tensor_dram(S * H * bpe)
        self.LAYER0_ATTN_OUT_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.LAYER0_ATTN_SCRATCH_DRAM = self.allocate_tensor_dram((D * S + max(D, 64) * S) * bpe)
        self.LAYER0_ATTN_RESULT_DRAM  = self.allocate_tensor_dram(S * H * bpe)
        # Shared-subroutine flash attention (mirrors compile_encoder's vision
        # pattern): the flash body is compiled ONCE and jumped to from every
        # (layer, head) call site instead of being statically re-emitted 18x
        # (one full seq_len=1024 attention body per layer was the actual root
        # cause of compile_prefix hanging for hours -- prefill_flash_attention_core
        # has no PBI/runtime-loop mode at all, only flash_attention_core does).
        # K/V need no per-head marshalling (MQA: same buffer for every head,
        # already fixed at LAYER0_K_PROJ_DRAM/LAYER0_V_PROJ_DRAM); only Q needs
        # copying into this fixed scratch slot before each jump, and OUTPUT
        # needs copying out after each return.
        self.LAYER0_FLASH_Q_DRAM = self.allocate_tensor_dram(S * D * bpe)
        self.LAYER0_FLASH_OUT_DRAM = self.allocate_tensor_dram(S * D * bpe)
        self.LAYER0_FLASH_ATTN_P_DRAM = self.allocate_tensor_dram(S * S * bpe)
        self.LAYER0_O_PROJ_DRAM   = self.allocate_tensor_dram(S * H * bpe)
        # Gated MLP, FF_HALF-split (see _weight_init_lm_prefix's down_proj comment for
        # why: avoids a strided-DMA K-split extraction that was the confirmed hang
        # trigger). Each half is independently computed/multiplied/down-projected.
        FF_HALF = I // 2
        self.LAYER0_MLP_GATE_LO_DRAM = self.allocate_tensor_dram(S * FF_HALF * bpe)
        self.LAYER0_MLP_GATE_HI_DRAM = self.allocate_tensor_dram(S * FF_HALF * bpe)
        self.LAYER0_MLP_UP_LO_DRAM   = self.allocate_tensor_dram(S * FF_HALF * bpe)
        self.LAYER0_MLP_UP_HI_DRAM   = self.allocate_tensor_dram(S * FF_HALF * bpe)
        self.LAYER0_MLP_MULT_LO_DRAM = self.allocate_tensor_dram(S * FF_HALF * bpe)
        self.LAYER0_MLP_MULT_HI_DRAM = self.allocate_tensor_dram(S * FF_HALF * bpe)
        self.LAYER0_MLP_DOWN_LO_OUT_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.LAYER0_MLP_DOWN_HI_OUT_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.LAYER0_MLP_DOWN_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.FINAL_NORM_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.LOGITS_DRAM     = self.allocate_tensor_dram(self.VOCAB_SIZE * bpe)
        if IS_VLM:
            # NOT in params.bin — must be re-allocated here (see skill gotchas).
            # store_identity_matrix always produces a fixed UE_VECTOR_SIZE(64)x64 identity;
            # it is reused as-is by the flash kernel regardless of head_dim/head_dim_pad.
            self.identity_addr = store_identity_matrix(self)
            self._tensor_init_vision()
        print(f"tensor_init done; tensor DRAM at 0x{self.get_tensor_dram_addr():X}")

    def _tensor_init_vision(self):
        """Allocate vision-encoder activation/scratch DRAM. Appended at the END of
        tensor_init (after all LM buffers) so no earlier LM buffer address shifts
        (run_from_bin.py must mirror this ordering — see skill gotchas)."""
        bpe = 2
        H, NH, D, DP, I, IP, S = (self.VIS_H, self.VIS_NH, self.VIS_D, self.VIS_DP,
                                   self.VIS_I, self.VIS_I_PAD, self.VIS_S)
        PK = self.VIS_PATCH_K   # 640 (588 padded to a multiple of 64), patch-embed matmul K
        HO = self.VIS_HEAD_OUT  # 2048, head projection output width

        # Patchified pixel input (host pre-patchifies raw pixels into [S, 588], mirroring the
        # torch reference's unfold+reshape, zero-padded to width PK=640 — no on-device
        # patchify is compiled here). Zero the whole buffer once so the pad columns
        # [588:640] the host never writes stay exactly 0 (matches the zero-padded kernel).
        self.VIS_PIXEL_IN_DRAM   = self.allocate_tensor_dram(S * PK * bpe)
        self.dma_write(DMA_DEVICE_H2C, self.VIS_PIXEL_IN_DRAM,
                        torch.zeros(S * PK, dtype=torch.bfloat16), S * PK * bpe)
        self.VIS_PATCH_PROJ_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.VIS_IO_A_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.VIS_IO_B_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.VIS_LN_OUT_DRAM = self.allocate_tensor_dram(S * H * bpe)
        # Q/K/V/attn-result are per-head-padded (D->DP=128, see _weight_init_vision's
        # _pad_proj) so every per-head DMA stride is AXI-beat aligned.
        HP = NH * DP
        self.VIS_Q_DRAM = self.allocate_tensor_dram(S * HP * bpe)
        self.VIS_K_DRAM = self.allocate_tensor_dram(S * HP * bpe)
        self.VIS_V_DRAM = self.allocate_tensor_dram(S * HP * bpe)
        self.VIS_ATTN_RESULT_DRAM = self.allocate_tensor_dram(S * HP * bpe)
        self.VIS_O_PROJ_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.VIS_RESIDUAL_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.VIS_MLP_INTER_DRAM = self.allocate_tensor_dram(S * IP * bpe)  # padded I->IP (see fc1/fc2)
        self.VIS_MLP_OUT_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.VIS_POST_LN_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.VIS_HEAD_OUT_DRAM = self.allocate_tensor_dram(S * HO * bpe)

        # Per-layer output snapshots (probe_nan_report): the real per-layer
        # output buffer (VIS_IO_A/B_DRAM) ping-pongs between two shared
        # buffers, so only the LAST layer's value survives a full run --
        # copy each layer's residual2 output to its own dedicated slot too,
        # so a single post-run readback can NaN-check every layer at once
        # instead of paying for 27 separate halt-recompile-rerun cycles.
        self.VIS_LAYER_SNAPSHOT_DRAM = [self.allocate_tensor_dram(S * H * bpe) for _ in range(27)]

        # LN zeros-replay buffer, shared by every LN call (see layer_norm_core_dram_pbi).
        self.vis_zeros_addr = self.allocate_tensor_dram(max(H, I) * bpe)
        self.dma_write(DMA_DEVICE_H2C, self.vis_zeros_addr,
                        torch.zeros(max(H, I), dtype=torch.bfloat16), max(H, I) * bpe)

        # §7 shared-subroutine per-head attention (proven smolvlm2/qwen2.5vl pattern): one
        # flash body reused across all (layer, head) call sites via strided-DMA head
        # marshalling. Buffers are padded to DP=128 (head_dim 72 -> 128, see hw_notes/
        # project_vision_attn_headdim_pad_unpad); only the real 72 columns are ever written
        # by the per-head gather/scatter, so the padded tail columns stay zero forever once
        # zero-initialized here — K's padded lanes dot to 0 and V's padded lanes contribute
        # 0 to the weighted sum, so attention math is unaffected and no explicit unpad
        # selection-matrix step is needed (the padding is self-annihilating by construction).
        self.VIS_FLASH_Q_DRAM = self.allocate_tensor_dram(S * DP * bpe)
        self.VIS_FLASH_K_DRAM = self.allocate_tensor_dram(S * DP * bpe)
        self.VIS_FLASH_V_DRAM = self.allocate_tensor_dram(S * DP * bpe)
        self.VIS_FLASH_OUT_DRAM = self.allocate_tensor_dram(S * DP * bpe)
        self.VIS_FLASH_ATTN_P_DRAM = self.allocate_tensor_dram(S * S * bpe)
        self.VIS_ATTN_SCRATCH_DRAM = self.allocate_tensor_dram((DP * S + DP * S) * bpe)
        zeros_dp = torch.zeros(S * DP, dtype=torch.bfloat16)
        for addr in (self.VIS_FLASH_Q_DRAM, self.VIS_FLASH_K_DRAM, self.VIS_FLASH_V_DRAM):
            self.dma_write(DMA_DEVICE_H2C, addr, zeros_dp, S * DP * bpe)
        print(f"    _tensor_init_vision done; tensor DRAM at 0x{self.get_tensor_dram_addr():X}")

    # ---- matmul dispatch ---------------------------------------------------
    def _matmul(self, M, K, N, A, proj, la, OUT, **kw):
        """Dispatch a (M,K)@(N,K)^T matmul against per-layer weight dict `la`, keyed by
        `proj` (e.g. 'q', 'k', 'v', 'o', 'gate', 'up', 'down'). All LM prefix weights are
        IF4 q4_64 per quant policy."""
        assert self.LM_QUANT == "q4_64", f"unsupported LM_QUANT={self.LM_QUANT}"
        return self.matmat_mul_core(
            M=M, K=K, N=N, A_DRAM_ADDR=A, B_DRAM_ADDR=la[f"{proj}_data"],
            OUTPUT_DRAM_ADDR=OUT, is_B_quantized=True, data_type=TYPE.IF4,
            SCALE_DRAM_ADDR=la[f"{proj}_scale"], **kw)

    def _dram_copy(self, size_bytes, src, dst):
        """DRAM->DRAM copy via a SRAM roundtrip, chunked through URAM_A. Used to
        stage per-layer K/V projections into the persistent KV-cache region."""
        bpe = 2
        elems = size_bytes // bpe
        chunk = min(URAM_NEAR_FULL_ELEMENTS, elems)
        sram = 0x00000
        for start, take in self.chunk_ranges(elems, chunk):
            off = start * bpe
            self.accelerator_memory_to_sram(src + off, sram, take)
            self.sram_to_accelerator_memory(sram, dst + off, take)

    def _dram_split_copy(self, rows, row_elems, col_offset, col_take, src, dst):
        """Extract a column slice [col_offset : col_offset+col_take) from a (rows,
        row_elems) row-major DRAM buffer into its own tightly-packed (rows, col_take)
        DRAM buffer, via a strided SRAM roundtrip. Used to materialize contiguous
        K-halves of the MLP intermediate (S, I) buffer for the down-proj K-split
        (matmat_mul_core_legacy cannot chunk K=16384 in one call; see compile_prefix)."""
        bpe = 2
        row_chunk = max(1, URAM_NEAR_FULL_ELEMENTS // col_take)
        sram = 0x00000
        for start, take in self.chunk_ranges(rows, row_chunk):
            self.accelerator_memory_to_sram(
                src + (start * row_elems + col_offset) * bpe, sram, take * col_take,
                stride_bytes_per_chunk=col_take * bpe, stride_jump_bytes=row_elems * bpe)
            self.sram_to_accelerator_memory(sram, dst + start * col_take * bpe, take * col_take)

    # ---- prefix LM stack (Gemma-2B, ported from pi05_torch_ref.prefix_forward /
    # joint_attention's `pre_tokens is not None` branch) ---------------------
    def build_prefix_attn_bias(self, seq_len, valid_len):
        """Bidirectional additive bias (seq_len, seq_len) bf16: 0 everywhere prefix
        tokens attend to each other; -1e36 on any column >= valid_len (padded lanes),
        matching pi05_torch_ref.build_prefix_attn_bias's placeholder (all-unmasked
        among real tokens, padding excluded). Not float('-inf') -- avoids NaN from
        exp(-inf - -inf) in the softmax kernel."""
        NEG = -1e36
        bias = torch.zeros((seq_len, seq_len), dtype=torch.bfloat16)
        if valid_len < seq_len:
            bias[:, valid_len:] = NEG
        return bias

    def embed_and_concat_prefix(self, token_ids, vision_embeddings=None, seq_len=1024):
        """Text-embedding lookup (host-side gather from self.embedding_table) concatenated
        with vision tokens (already-projected (n_vis, hidden) bf16, e.g. from
        compile_encoder's output), padded to seq_len. Writes the result to
        LAYER0_INPUT_DRAM. Returns valid_len (vision + text, before padding)."""
        H = self.HIDDEN_SIZE
        vis = vision_embeddings if vision_embeddings is not None else torch.zeros((0, H), dtype=torch.bfloat16)
        n_vis = vis.shape[0]

        tid = torch.tensor(token_ids, dtype=torch.long)
        text_embed = self.embedding_table[tid].to(torch.bfloat16)   # (n_text, H) host-side gather

        valid_len = n_vis + text_embed.shape[0]
        assert valid_len <= seq_len, f"prefix valid_len={valid_len} exceeds seq_len={seq_len}"

        # Padding rows [valid_len:seq_len] must NOT be exact zero: rms_norm_core has
        # no epsilon (confirmed by reading user_dma_core.py -- MODE_RSQRT computes
        # sqrt(N)/sqrt(sum(x_i^2)) directly, no +eps), so an all-zero row hits
        # rsqrt(0)=inf, then 0*inf=NaN for that row's "normalized" output. That NaN
        # then contaminates every REAL row too: attention's masked columns get
        # ~0 softmax weight but 0*NaN=NaN in IEEE arithmetic, not 0 -- so a single
        # NaN padding column poisons the weighted sum for every query row. This is
        # exactly the mechanism confirmed via debug_stepwise_prefix.py --dump
        # (checkpoints 14/15/16 all 100% NaN). smolvlm2_test.py hit the identical
        # problem and fixes it the same way: epsilon-fill padding rows instead of
        # leaving them at exact zero (see its "epsilon-fill INPUT padding rows" step).
        full = torch.full((seq_len, H), 1e-6, dtype=torch.bfloat16)
        full[:n_vis] = vis
        full[n_vis:valid_len] = text_embed
        self.dma_to_accelerator_memory(self.LAYER0_INPUT_DRAM, full)
        return valid_len

    def compile_prefix(self, seq_len, valid_len=None):
        """18-layer Gemma-2B prefix stack: RMSNorm -> MQA flash-attn (bidirectional
        bias) -> residual -> RMSNorm -> gated-GELU MLP -> residual. Per-layer K/V
        projections are staged into the persistent LAYER0_K_DRAM/LAYER0_V_DRAM cache
        (see tensor_init's KV_LAYER_STRIDE/KV_HEAD_STRIDE) for later reuse by the
        action-expert suffix stack (out of scope here).

        Ports pi05_torch_ref.prefix_forward + joint_attention's `pre_tokens is not
        None` branch. suf_tokens branch is out of scope."""
        S, H, I, D = seq_len, self.HIDDEN_SIZE, self.INTERMEDIATE_SIZE, self.HEAD_DIM
        NH, NKV, KV = self.NUM_HEADS, self.NUM_KV_HEADS, self.NUM_KV_HEADS * self.HEAD_DIM
        assert NKV == 1, "compile_prefix assumes pure MQA (num_kv_heads=1); broadcast via num_q_heads"
        bpe = 2

        self._debug_counter = 0
        self._debug_halt_info = None

        valid_len = valid_len if valid_len is not None else S
        self.prefix_bias_dram = store_weight(self, self.build_prefix_attn_bias(S, valid_len))

        bpe = 2
        # Dedicated, non-aliased output buffers for the two residual adds below.
        # eltwise_add_core_dram(A, B, OUT) with OUT == B (in-place) was the confirmed
        # hang trigger (checkpoint layer0_residual2) -- real streaming/DMA hardware
        # reading and writing the same address in one op is a hazard, not just a
        # correctness footgun. Every add below now writes to a buffer distinct from
        # both its inputs.
        self.LAYER0_ATTN_RESIDUAL_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.LAYER0_LAYER_OUT_DRAM = self.allocate_tensor_dram(S * H * bpe)
        # Per-layer snapshots (LAYER0_LAYER_OUT_DRAM itself is reused/overwritten
        # every layer) so a post-run readback can CPU-vs-HW SNR-check every
        # layer's output at once -- same pattern as VIS_LAYER_SNAPSHOT_DRAM.
        # layer0-only op-by-op snapshots (layer0's per-op scratch buffers, e.g.
        # LAYER0_Q_DRAM, get overwritten by every later layer's same op -- these
        # dedicated copies survive the full 18-layer run so a single post-run
        # readback can op-by-op SNR-check exactly where within layer0 things
        # first diverge from the CPU reference, without 19 separate debug-stop runs).
        # DISABLED by default (self._prefix_snap) -- these ~98MB of buffers push
        # the action-expert stack ~98MB higher, the only diff vs the clean --debug
        # run. Allocated only when PREFIX_SNAPSHOTS=True.
        if getattr(self, "PREFIX_SNAPSHOTS", False):
            self.PREFIX_LAYER_SNAPSHOT_DRAM = [self.allocate_tensor_dram(S * H * bpe) for _ in range(self.NUM_LAYERS)]
            self.PREFIX_L0_SNAPSHOT_DRAM = {
                name: self.allocate_tensor_dram(size * bpe) for name, size in (
                    ("ln1", S * H), ("q_proj", S * H), ("k_proj", S * KV), ("v_proj", S * KV),
                    ("q_permute", S * H),
                    ("head0", S * D), ("head1", S * D), ("head2", S * D), ("head3", S * D),
                    ("head4", S * D), ("head5", S * D), ("head6", S * D), ("head7", S * D),
                    ("attn_permute", S * H), ("o_proj_residual", S * H), ("ln2", S * H),
                    ("mlp_lo", S * H), ("mlp_hi", S * H), ("mlp_down", S * H),
                )
            }
        else:
            self.PREFIX_LAYER_SNAPSHOT_DRAM = None
            self.PREFIX_L0_SNAPSHOT_DRAM = None

        # Fresh register/inst-pointer allocation per stage (start_capture does
        # NOT reset these per-process counters; drift across stages hands out
        # bad indices -- see compile_denoise_loop's reset for the full writeup).
        self.reset_isa_reg_counter()
        self.reset_inst_ptr_counter()

        # PREFIX_SNAPSHOTS: debug-only per-layer/op SNR snapshot buffers. When
        # OFF (default), skip both the ~98MB of snapshot DRAM allocations AND the
        # per-op _dram_copy instructions -- this keeps compile_prefix from
        # shoving the action-expert buffers ~98MB higher in tensor DRAM (the
        # ONLY thing that differs between a clean --debug denoise run and the
        # NaN'ing full run). Set True to re-enable the per-op SNR report.
        self._prefix_snap = getattr(self, "PREFIX_SNAPSHOTS", False)

        # PBI dynamic-M loop (mirrors compile_encoder's vis_S_reg): without this,
        # every matmul/RMSNorm below compiles a fully-unrolled static instruction
        # stream per M=1024 row-chunk, which for 18 layers blew the compiled
        # program up to ~684MB (vs. vision's 745KB for 27 layers) and triggered a
        # DMA transfer-size failure. gpr_M_reg makes the outer row loop a runtime
        # trip count instead of static unrolling.
        prefix_S_reg = self.alloc_isa_reg()
        self.generate_instruction_add_set(prefix_S_reg, S)

        # Shared-subroutine flash attention (see tensor_init's LAYER0_FLASH_*
        # buffers): the flash body is compiled ONCE after the main per-layer loop
        # ends (below a HALT) and jumped to from every (layer, head) call site,
        # exactly like compile_encoder's vis_sub_start pattern. prefill_flash_
        # attention_core (the non-PBI all-heads-at-once convenience wrapper) has
        # no runtime-loop mode and was statically re-emitting a full seq_len=1024
        # attention body per layer -- 18 of those never finished compiling.
        prefix_prog_base = self.get_program_dram_addr()
        prefix_gpr_bucket = self.alloc_isa_reg()
        prefix_gpr_ret = self.alloc_isa_reg()
        prefix_call_sites: list[int] = []
        prefix_num_buckets = S // UE_VECTOR_SIZE

        try:
            for layer_idx in range(self.NUM_LAYERS):
                la = self.lm_layer_addrs[layer_idx]
                h_in = self.LAYER0_INPUT_DRAM if layer_idx == 0 else self.LAYER0_LAYER_OUT_DRAM

                # 1. pre-attention RMSNorm
                self.rms_norm_core_dram(M=S, N=H, A_DRAM_ADDR=h_in,
                                         OUTPUT_DRAM_ADDR=self.LAYER0_PRE_NORM_DRAM, GAMMA_DRAM_ADDR=la["ln1"],
                                         gpr_M_reg=prefix_S_reg)
                self._debug_op(f"layer{layer_idx}_ln1", self.LAYER0_PRE_NORM_DRAM, S * H, shape=(S, H))
                if layer_idx == 0 and self._prefix_snap:
                    self._dram_copy(S * H * bpe, self.LAYER0_PRE_NORM_DRAM, self.PREFIX_L0_SNAPSHOT_DRAM["ln1"])

                # 2. Q/K/V projections (MQA: K/V project to a single head_dim, not NH*D)
                self._matmul(M=S, K=H, N=H, A=self.LAYER0_PRE_NORM_DRAM, proj="q", la=la, OUT=self.LAYER0_Q_DRAM, gpr_M_reg=prefix_S_reg)
                self._matmul(M=S, K=H, N=KV, A=self.LAYER0_PRE_NORM_DRAM, proj="k", la=la, OUT=self.LAYER0_K_PROJ_DRAM, gpr_M_reg=prefix_S_reg)
                self._matmul(M=S, K=H, N=KV, A=self.LAYER0_PRE_NORM_DRAM, proj="v", la=la, OUT=self.LAYER0_V_PROJ_DRAM, gpr_M_reg=prefix_S_reg)
                self._debug_op(f"layer{layer_idx}_qkv_proj", self.LAYER0_Q_DRAM, S * H, shape=(S, H))
                if layer_idx == 0 and self._prefix_snap:
                    self._dram_copy(S * H * bpe, self.LAYER0_Q_DRAM, self.PREFIX_L0_SNAPSHOT_DRAM["q_proj"])
                    self._dram_copy(S * KV * bpe, self.LAYER0_K_PROJ_DRAM, self.PREFIX_L0_SNAPSHOT_DRAM["k_proj"])
                    self._dram_copy(S * KV * bpe, self.LAYER0_V_PROJ_DRAM, self.PREFIX_L0_SNAPSHOT_DRAM["v_proj"])

                # 3. permute Q from (seq, heads, head_dim) -> (heads, seq, head_dim); K/V
                # already (seq, head_dim) since num_kv_heads=1 == the layout
                # prefill_flash_attention_core expects for a single KV head.
                smart_bf16_permute_core(self, (S, NH, D), [1, 0, 2],
                                         self.LAYER0_Q_DRAM, self.LAYER0_Q_PERM_DRAM)
                self._debug_op(f"layer{layer_idx}_q_permute", self.LAYER0_Q_PERM_DRAM, S * H, shape=(S, H))
                if layer_idx == 0 and self._prefix_snap:
                    self._dram_copy(S * H * bpe, self.LAYER0_Q_PERM_DRAM, self.PREFIX_L0_SNAPSHOT_DRAM["q_permute"])

                # 4. stage this layer's K/V into the persistent KV cache for downstream reuse.
                k_cache_addr = self.LAYER0_K_DRAM + layer_idx * self.KV_LAYER_STRIDE
                v_cache_addr = self.LAYER0_V_DRAM + layer_idx * self.KV_LAYER_STRIDE
                self._dram_copy(S * KV * bpe, self.LAYER0_K_PROJ_DRAM, k_cache_addr)
                self._dram_copy(S * KV * bpe, self.LAYER0_V_PROJ_DRAM, v_cache_addr)
                self._debug_op(f"layer{layer_idx}_kv_cache", k_cache_addr, S * KV, shape=(S, KV))

                # 5. MQA flash attention, bidirectional bias (no causal flag), per head
                # via the shared subroutine: Q for this head is copied (contiguous,
                # already separated by the step-3 permute) into the fixed
                # LAYER0_FLASH_Q_DRAM scratch, then jump into the one compiled flash
                # body, then the (fixed-address) output is copied into this head's
                # slot of LAYER0_ATTN_OUT_DRAM. K/V need no marshalling -- MQA means
                # the same LAYER0_K_PROJ_DRAM/LAYER0_V_PROJ_DRAM buffer (already
                # current for this layer, see step 2) is valid for every head, and
                # the subroutine's K/V addresses are fixed to those same buffers.
                head_bytes = S * D * bpe
                for h in range(NH):
                    self._dram_copy(head_bytes, self.LAYER0_Q_PERM_DRAM + h * head_bytes, self.LAYER0_FLASH_Q_DRAM)
                    self.generate_instruction_add_set(prefix_gpr_bucket, prefix_num_buckets)
                    self.pad_capture_to_64b_boundary()
                    return_word_addr = ue_35bit_addr_shifter(
                        prefix_prog_base + (self.capture_count + 2) * INSTRUCTION_SIZE_BYTES)
                    self.generate_instruction_add_set(prefix_gpr_ret, return_word_addr)
                    prefix_call_sites.append(self.capture_count)
                    self.generate_instruction_jump_abs(target_instruction_word_addr=0)
                    self._dram_copy(head_bytes, self.LAYER0_FLASH_OUT_DRAM, self.LAYER0_ATTN_OUT_DRAM + h * head_bytes)
                    self._debug_op(f"layer{layer_idx}_head{h}", self.LAYER0_ATTN_OUT_DRAM + h * head_bytes, S * D, shape=(S, D))
                    if layer_idx == 0 and self._prefix_snap:
                        self._dram_copy(head_bytes, self.LAYER0_ATTN_OUT_DRAM + h * head_bytes,
                                         self.PREFIX_L0_SNAPSHOT_DRAM[f"head{h}"])

                # 6. permute attn output (heads, seq, head_dim) -> (seq, heads*head_dim)
                smart_bf16_permute_core(self, (NH, S, D), [1, 0, 2],
                                         self.LAYER0_ATTN_OUT_DRAM, self.LAYER0_ATTN_RESULT_DRAM)
                self._debug_op(f"layer{layer_idx}_attn_permute", self.LAYER0_ATTN_RESULT_DRAM, S * H, shape=(S, H))
                if layer_idx == 0 and self._prefix_snap:
                    self._dram_copy(S * H * bpe, self.LAYER0_ATTN_RESULT_DRAM, self.PREFIX_L0_SNAPSHOT_DRAM["attn_permute"])

                # 7. output projection + residual (non-aliased: OUT distinct from both inputs)
                self._matmul(M=S, K=H, N=H, A=self.LAYER0_ATTN_RESULT_DRAM, proj="o", la=la, OUT=self.LAYER0_O_PROJ_DRAM, gpr_M_reg=prefix_S_reg)
                eltwise_add_core_dram(self, S * H, h_in, self.LAYER0_O_PROJ_DRAM, self.LAYER0_ATTN_RESIDUAL_DRAM)
                self._debug_op(f"layer{layer_idx}_o_proj_residual", self.LAYER0_ATTN_RESIDUAL_DRAM, S * H, shape=(S, H))
                if layer_idx == 0 and self._prefix_snap:
                    self._dram_copy(S * H * bpe, self.LAYER0_ATTN_RESIDUAL_DRAM, self.PREFIX_L0_SNAPSHOT_DRAM["o_proj_residual"])

                # 8. pre-FFW RMSNorm
                self.rms_norm_core_dram(M=S, N=H, A_DRAM_ADDR=self.LAYER0_ATTN_RESIDUAL_DRAM,
                                         OUTPUT_DRAM_ADDR=self.LAYER0_PRE_NORM_DRAM, GAMMA_DRAM_ADDR=la["ln2"],
                                         gpr_M_reg=prefix_S_reg)
                self._debug_op(f"layer{layer_idx}_ln2", self.LAYER0_PRE_NORM_DRAM, S * H, shape=(S, H))
                if layer_idx == 0 and self._prefix_snap:
                    self._dram_copy(S * H * bpe, self.LAYER0_PRE_NORM_DRAM, self.PREFIX_L0_SNAPSHOT_DRAM["ln2"])

                # 9. gated-GELU MLP + residual, FF_HALF-split (parakeet_test.py pattern,
                # adapted for the gated variant -- see _weight_init_lm_prefix's comment
                # for why: matmat_mul_core_pbi can't do K=16384 in one call, and the
                # strided-DMA extraction alternative (_dram_split_copy) was the
                # confirmed hang trigger). Each half computed/multiplied/down-projected
                # independently so down_proj's K-input is naturally contiguous from the
                # moment it's written -- no slicing step exists to hang on.
                FF_HALF = I // 2
                self._matmul(M=S, K=H, N=FF_HALF, A=self.LAYER0_PRE_NORM_DRAM, proj="gate_lo", la=la,
                             OUT=self.LAYER0_MLP_GATE_LO_DRAM, gelu_enable=True, gpr_M_reg=prefix_S_reg)
                self._matmul(M=S, K=H, N=FF_HALF, A=self.LAYER0_PRE_NORM_DRAM, proj="up_lo", la=la,
                             OUT=self.LAYER0_MLP_UP_LO_DRAM, gpr_M_reg=prefix_S_reg)
                eltwise_mul_core_dram(self, S * FF_HALF, self.LAYER0_MLP_GATE_LO_DRAM, self.LAYER0_MLP_UP_LO_DRAM, self.LAYER0_MLP_MULT_LO_DRAM)
                self._matmul(M=S, K=FF_HALF, N=H, A=self.LAYER0_MLP_MULT_LO_DRAM, proj="down_lo", la=la,
                             OUT=self.LAYER0_MLP_DOWN_LO_OUT_DRAM, gpr_M_reg=prefix_S_reg)
                self._debug_op(f"layer{layer_idx}_mlp_lo", self.LAYER0_MLP_DOWN_LO_OUT_DRAM, S * H, shape=(S, H))
                if layer_idx == 0 and self._prefix_snap:
                    self._dram_copy(S * H * bpe, self.LAYER0_MLP_DOWN_LO_OUT_DRAM, self.PREFIX_L0_SNAPSHOT_DRAM["mlp_lo"])

                self._matmul(M=S, K=H, N=FF_HALF, A=self.LAYER0_PRE_NORM_DRAM, proj="gate_hi", la=la,
                             OUT=self.LAYER0_MLP_GATE_HI_DRAM, gelu_enable=True, gpr_M_reg=prefix_S_reg)
                self._matmul(M=S, K=H, N=FF_HALF, A=self.LAYER0_PRE_NORM_DRAM, proj="up_hi", la=la,
                             OUT=self.LAYER0_MLP_UP_HI_DRAM, gpr_M_reg=prefix_S_reg)
                eltwise_mul_core_dram(self, S * FF_HALF, self.LAYER0_MLP_GATE_HI_DRAM, self.LAYER0_MLP_UP_HI_DRAM, self.LAYER0_MLP_MULT_HI_DRAM)
                self._matmul(M=S, K=FF_HALF, N=H, A=self.LAYER0_MLP_MULT_HI_DRAM, proj="down_hi", la=la,
                             OUT=self.LAYER0_MLP_DOWN_HI_OUT_DRAM, gpr_M_reg=prefix_S_reg)
                self._debug_op(f"layer{layer_idx}_mlp_hi", self.LAYER0_MLP_DOWN_HI_OUT_DRAM, S * H, shape=(S, H))
                if layer_idx == 0 and self._prefix_snap:
                    self._dram_copy(S * H * bpe, self.LAYER0_MLP_DOWN_HI_OUT_DRAM, self.PREFIX_L0_SNAPSHOT_DRAM["mlp_hi"])

                eltwise_add_core_dram(self, S * H, self.LAYER0_MLP_DOWN_LO_OUT_DRAM, self.LAYER0_MLP_DOWN_HI_OUT_DRAM, self.LAYER0_MLP_DOWN_DRAM)
                self._debug_op(f"layer{layer_idx}_mlp_down", self.LAYER0_MLP_DOWN_DRAM, S * H, shape=(S, H))
                if layer_idx == 0 and self._prefix_snap:
                    self._dram_copy(S * H * bpe, self.LAYER0_MLP_DOWN_DRAM, self.PREFIX_L0_SNAPSHOT_DRAM["mlp_down"])
                # non-aliased: OUT (LAYER0_LAYER_OUT_DRAM) distinct from both inputs
                eltwise_add_core_dram(self, S * H, self.LAYER0_ATTN_RESIDUAL_DRAM, self.LAYER0_MLP_DOWN_DRAM, self.LAYER0_LAYER_OUT_DRAM)
                self._debug_op(f"layer{layer_idx}_residual2", self.LAYER0_LAYER_OUT_DRAM, S * H, shape=(S, H))
                if self._prefix_snap:
                    self._dram_copy(S * H * bpe, self.LAYER0_LAYER_OUT_DRAM, self.PREFIX_LAYER_SNAPSHOT_DRAM[layer_idx])

            # Main per-layer program ends here; the shared flash-attention subroutine
            # (jumped to from every per-head call site above) is compiled once below,
            # exactly like compile_encoder's vis_sub_start pattern.
            self.generate_instruction_halt()
        except _DebugStop:
            pass   # halt already emitted by _debug_op; fall through to the subroutine compile below.

        prefix_sub_start, _prefix_flops = self.flash_attention_core(
            head_dim=D, seq_len=S,
            Q_DRAM_ADDR=self.LAYER0_FLASH_Q_DRAM, K_DRAM_ADDR=self.LAYER0_K_PROJ_DRAM,
            V_DRAM_ADDR=self.LAYER0_V_PROJ_DRAM, OUTPUT_DRAM_ADDR=self.LAYER0_FLASH_OUT_DRAM,
            SCRATCH_DRAM_ADDR=self.LAYER0_ATTN_SCRATCH_DRAM, ATTN_P_DRAM_ADDR=self.LAYER0_FLASH_ATTN_P_DRAM,
            IDENTITY_DRAM_ADDR=self.identity_addr, BIAS_DRAM_ADDR=self.prefix_bias_dram,
            gpr_bucket_idx=prefix_gpr_bucket, num_buckets=prefix_num_buckets, gpr_ret_id=prefix_gpr_ret)
        for _idx in prefix_call_sites:
            self._patch_jump_immediate(_idx, ue_35bit_addr_shifter(prefix_sub_start))

        self.release_isa_reg()  # prefix_gpr_ret
        self.release_isa_reg()  # prefix_gpr_bucket
        self.release_isa_reg()  # prefix_S_reg
        print(f"compile_prefix: {self.NUM_LAYERS} layers compiled, seq_len={S}, valid_len={valid_len}")

        # ---- BUGFIX (interface reconciliation): the action-expert stack
        # (compile_suffix_step / tensor_init_action_expert) expects
        # self.PREFIX_SEQ_LEN + self.prefix_k_cache_addr[l]/prefix_v_cache_addr[l]
        # per-layer DRAM addresses. The real per-layer K/V cache was staged above
        # into LAYER0_K_DRAM/LAYER0_V_DRAM + layer_idx*KV_LAYER_STRIDE (each layer's
        # slice already has shape (S, KV)=(S, NUM_KV_HEADS*HEAD_DIM)=(S, HEAD_DIM)
        # since NUM_KV_HEADS==1 -- exactly the (PREFIX_SEQ_LEN, HEAD_DIM) shape the
        # action-expert code expects). Point the expected attrs directly at those
        # real addresses so tensor_init_action_expert's placeholder fallback never
        # triggers.
        self.PREFIX_SEQ_LEN = S
        self.prefix_valid_len = valid_len
        self.prefix_k_cache_addr = [self.LAYER0_K_DRAM + l * self.KV_LAYER_STRIDE for l in range(self.NUM_LAYERS)]
        self.prefix_v_cache_addr = [self.LAYER0_V_DRAM + l * self.KV_LAYER_STRIDE for l in range(self.NUM_LAYERS)]

        return self.LAYER0_LAYER_OUT_DRAM

    # ---- prefill -----------------------------------------------------------
    def compile_prefill(self, seq_len):
        """Standard decoder loop driven by self.OPS. Fill _matmul/weight_init first.
        Confirm the prefill PBI mode matches the current branch."""
        S, H, I, D = seq_len, self.HIDDEN_SIZE, self.INTERMEDIATE_SIZE, self.HEAD_DIM
        for layer_idx in range(self.NUM_LAYERS):
            la = self.lm_layer_addrs[layer_idx]
            h_in = self.LAYER0_INPUT_DRAM if layer_idx == 0 else self.LAYER0_MLP_DOWN_DRAM
            # 1. input norm (fused post-add for layers 1+)
            # 2. q/k/v proj   3. rope   4. attn (GQA, causal)   5. o proj
            # 6. post-attn norm   7. mlp (gated_silu/gelu)
            # See references/op-library.md for the exact call order + flags.
            raise NotImplementedError("wire the op chain from references/op-library.md")

    # ---- decode ------------------------------------------------------------
    def compile_decode(self):
        """Single-token decode loop. Confirm the decode PBI mode matches the branch."""
        raise NotImplementedError("wire the decode op chain")

    # ---- VLM hook ----------------------------------------------------------
    def compile_encoder(self):
        """Compile the 27-layer SigLIP So400m/14 vision encoder (bidirectional, no RoPE,
        no causal mask — see hw_notes). Structure follows the proven smolvlm2_test.py §7
        shared-subroutine-flash pattern: PBI row loops for matmul/layer_norm/eltwise
        (gpr_M_reg), one flash body shared across every (layer, head) call site via
        strided-DMA head marshalling, head_dim padded 72->128 for the flash kernel (see
        _tensor_init_vision for why no explicit unpad selection-matrix is needed). All
        matmul weights are IF4 q4_64 (quant policy) -> quantized_matmul dispatch.
        """
        from user_dma_core import TYPE
        S, H, NH, D, DP, IP = (self.VIS_S, self.VIS_H, self.VIS_NH, self.VIS_D, self.VIS_DP,
                                self.VIS_I_PAD)
        bpe = 2

        # layer_norm_core_dram_pbi chunking (replicated so we prime n_chunks correctly).
        _ln_ops_per_row = 6
        _ln_chunk = min(URAM_NEAR_FULL_ELEMENTS // H, S, (256 - 4) // _ln_ops_per_row)
        while S % _ln_chunk != 0:
            _ln_chunk -= 1
        ln_n_chunks = S // _ln_chunk

        self.start_capture()
        self._debug_counter = 0
        self._debug_halt_info = None

        # Fresh register/inst-pointer counters per stage (see compile_denoise_loop).
        self.reset_isa_reg_counter()
        self.reset_inst_ptr_counter()

        vis_S_reg = self.alloc_isa_reg()
        vis_ln_chunks = self.alloc_isa_reg()
        self.generate_instruction_add_set(vis_S_reg, S)
        self.generate_instruction_add_set(vis_ln_chunks, ln_n_chunks)

        def vis_matmul(M, K, N, A, la, proj, OUT, bias=None, **kw):
            self.matmat_mul_core(M=M, K=K, N=N, A_DRAM_ADDR=A, B_DRAM_ADDR=la[f'{proj}_data'],
                OUTPUT_DRAM_ADDR=OUT, is_B_quantized=True, data_type=TYPE.IF4,
                SCALE_DRAM_ADDR=la[f'{proj}_scale'], C_DRAM_ADDR=bias, bias_mode="broadcast_N",
                gpr_M_reg=vis_S_reg, **kw)

        # §7 shared-subroutine attention: the per-head flash body is compiled ONCE after the
        # encoder HALT; every per-(layer,head) call site marshals its head's [S, D] Q/K/V
        # (padded to [S, DP]) into the fixed VIS_FLASH buffers and jumps in.
        vis_prog_base = self.get_program_dram_addr()
        vis_gpr_bucket = self.alloc_isa_reg()
        vis_gpr_ret = self.alloc_isa_reg()
        vis_call_sites: list[int] = []
        vis_num_buckets = S // UE_VECTOR_SIZE

        try:
            # === Patch embedding: patchified pixels [S, 588] -> [S, 1152] (+ pos_embedding) ===
            vis_matmul(S, self.VIS_PATCH_K, H, self.VIS_PIXEL_IN_DRAM,
                {'embed_data': self.vis_embed_data, 'embed_scale': self.vis_embed_scale}, 'embed',
                self.VIS_PATCH_PROJ_DRAM, bias=self.vis_embed_bias)
            eltwise_add_core_dram(self, size=S * H, A_DRAM_ADDR=self.VIS_PATCH_PROJ_DRAM,
                B_DRAM_ADDR=self.vis_pos_embed, OUTPUT_DRAM_ADDR=self.VIS_IO_A_DRAM)
            self._debug_op("patch_embed_pos", self.VIS_IO_A_DRAM, S * H, shape=(S, H))

            for layer_idx, la in enumerate(self.vis_layer_addrs):
                h_in  = self.VIS_IO_A_DRAM if layer_idx % 2 == 0 else self.VIS_IO_B_DRAM
                h_out = self.VIS_IO_B_DRAM if layer_idx % 2 == 0 else self.VIS_IO_A_DRAM
                # LN0 (PBI)
                self.layer_norm_core_dram(M=S, N=H, A_DRAM_ADDR=h_in, OUTPUT_DRAM_ADDR=self.VIS_LN_OUT_DRAM,
                    GAMMA_DRAM_ADDR=la['ln0_w'], BETA_DRAM_ADDR=la['ln0_b'], gpr_M_reg=vis_ln_chunks,
                    ZEROS_DRAM_ADDR=self.vis_zeros_addr)
                self._debug_op(f"layer{layer_idx}_ln0", self.VIS_LN_OUT_DRAM, S * H, shape=(S, H))
                # Q/K/V projections (PBI, IF4). N=NH*DP: weights are pre-padded per-head
                # D->DP=128 (see _weight_init_vision's _pad_proj) so the buffers below are
                # already head-block-aligned at DP=128, no separate real/padded copy needed.
                HP = NH * DP
                for proj, dst in [('q', self.VIS_Q_DRAM), ('k', self.VIS_K_DRAM), ('v', self.VIS_V_DRAM)]:
                    vis_matmul(S, H, HP, self.VIS_LN_OUT_DRAM, la, proj, dst, bias=la[f'{proj}_bias'])
                # Per-head bidirectional flash attention (no mask, no RoPE). Each head's block is
                # a full DP=128-wide (256B) column slice -> every DMA stride below is AXI-beat
                # (32B) aligned, unlike a bare D=72 (144B) slice.
                elems = S * DP
                col_stride = DP * bpe   # one head's column block width (aligned)
                row_jump = HP * bpe     # full [S, HP] row stride
                for h in range(NH):
                    col = h * col_stride
                    for src, dst in ((self.VIS_Q_DRAM + col, self.VIS_FLASH_Q_DRAM),
                                     (self.VIS_K_DRAM + col, self.VIS_FLASH_K_DRAM),
                                     (self.VIS_V_DRAM + col, self.VIS_FLASH_V_DRAM)):
                        self.accelerator_memory_to_sram(src, 0x00000, elems,
                            stride_bytes_per_chunk=col_stride, stride_jump_bytes=row_jump)
                        self.sram_to_accelerator_memory(0x00000, dst, elems)
                    self.generate_instruction_add_set(vis_gpr_bucket, S // UE_VECTOR_SIZE)
                    self.pad_capture_to_64b_boundary()
                    return_word_addr = ue_35bit_addr_shifter(
                        vis_prog_base + (self.capture_count + 2) * INSTRUCTION_SIZE_BYTES)
                    self.generate_instruction_add_set(vis_gpr_ret, return_word_addr)
                    vis_call_sites.append(self.capture_count)
                    self.generate_instruction_jump_abs(target_instruction_word_addr=0)
                    self.accelerator_memory_to_sram(self.VIS_FLASH_OUT_DRAM, 0x00000, elems)
                    self.sram_to_accelerator_memory(0x00000, self.VIS_ATTN_RESULT_DRAM + col, elems,
                        stride_bytes_per_chunk=col_stride, stride_jump_bytes=row_jump)
                # O projection + residual + LN1 (PBI)
                vis_matmul(S, HP, H, self.VIS_ATTN_RESULT_DRAM, la, 'o', self.VIS_O_PROJ_DRAM, bias=la['o_bias'])
                self._debug_op(f"layer{layer_idx}_o_proj", self.VIS_O_PROJ_DRAM, S * H, shape=(S, H))
                eltwise_add_core_dram(self, size=S * H, A_DRAM_ADDR=h_in, B_DRAM_ADDR=self.VIS_O_PROJ_DRAM,
                    OUTPUT_DRAM_ADDR=self.VIS_RESIDUAL_DRAM)
                self._debug_op(f"layer{layer_idx}_residual1", self.VIS_RESIDUAL_DRAM, S * H, shape=(S, H))
                self.layer_norm_core_dram(M=S, N=H, A_DRAM_ADDR=self.VIS_RESIDUAL_DRAM, OUTPUT_DRAM_ADDR=self.VIS_LN_OUT_DRAM,
                    GAMMA_DRAM_ADDR=la['ln1_w'], BETA_DRAM_ADDR=la['ln1_b'], gpr_M_reg=vis_ln_chunks,
                    ZEROS_DRAM_ADDR=self.vis_zeros_addr)
                self._debug_op(f"layer{layer_idx}_ln1", self.VIS_LN_OUT_DRAM, S * H, shape=(S, H))
                # MLP: Dense_0 + GELU (sigmoid-approx — the engine's only hardware GELU; the
                # reference uses tanh-approx GELU, a small documented numeric deviation),
                # Dense_1, residual.
                vis_matmul(S, H, IP, self.VIS_LN_OUT_DRAM, la, 'fc1', self.VIS_MLP_INTER_DRAM,
                    bias=la['fc1_bias'], gelu_enable=True)
                vis_matmul(S, IP, H, self.VIS_MLP_INTER_DRAM, la, 'fc2', self.VIS_MLP_OUT_DRAM, bias=la['fc2_bias'])
                self._debug_op(f"layer{layer_idx}_mlp_out", self.VIS_MLP_OUT_DRAM, S * H, shape=(S, H))
                eltwise_add_core_dram(self, size=S * H,
                    A_DRAM_ADDR=self.VIS_RESIDUAL_DRAM, B_DRAM_ADDR=self.VIS_MLP_OUT_DRAM, OUTPUT_DRAM_ADDR=h_out)
                self._debug_op(f"layer{layer_idx}_residual2", h_out, S * H, shape=(S, H))
                self._dram_copy(S * H * bpe, h_out, self.VIS_LAYER_SNAPSHOT_DRAM[layer_idx])

            # Final encoder_norm (PBI) + head projection (IF4).
            final_vis = self.VIS_IO_A_DRAM if len(self.vis_layer_addrs) % 2 == 0 else self.VIS_IO_B_DRAM
            self.layer_norm_core_dram(M=S, N=H, A_DRAM_ADDR=final_vis, OUTPUT_DRAM_ADDR=self.VIS_POST_LN_DRAM,
                GAMMA_DRAM_ADDR=self.vis_encoder_norm_w, BETA_DRAM_ADDR=self.vis_encoder_norm_b,
                gpr_M_reg=vis_ln_chunks, ZEROS_DRAM_ADDR=self.vis_zeros_addr)
            self._debug_op("encoder_norm", self.VIS_POST_LN_DRAM, S * H, shape=(S, H))
            vis_matmul(S, H, self.VIS_HEAD_OUT, self.VIS_POST_LN_DRAM,
                {'head_data': self.vis_head_data, 'head_scale': self.vis_head_scale}, 'head',
                self.VIS_HEAD_OUT_DRAM, bias=self.vis_head_bias)
            self._debug_op("head_out", self.VIS_HEAD_OUT_DRAM, S * self.VIS_HEAD_OUT, shape=(S, self.VIS_HEAD_OUT))

            self.generate_instruction_halt()   # encoder ends; shared flash body follows.
        except _DebugStop:
            pass   # halt already emitted by _debug_op; fall through to the subroutine compile below.

        vis_sub_start, _vis_flops = self.flash_attention_core(head_dim=DP, seq_len=S,
            Q_DRAM_ADDR=self.VIS_FLASH_Q_DRAM, K_DRAM_ADDR=self.VIS_FLASH_K_DRAM,
            V_DRAM_ADDR=self.VIS_FLASH_V_DRAM, OUTPUT_DRAM_ADDR=self.VIS_FLASH_OUT_DRAM,
            SCRATCH_DRAM_ADDR=self.VIS_ATTN_SCRATCH_DRAM, ATTN_P_DRAM_ADDR=self.VIS_FLASH_ATTN_P_DRAM,
            IDENTITY_DRAM_ADDR=self.identity_addr,
            gpr_bucket_idx=vis_gpr_bucket, num_buckets=vis_num_buckets, gpr_ret_id=vis_gpr_ret)
        for _idx in vis_call_sites:
            self._patch_jump_immediate(_idx, ue_35bit_addr_shifter(vis_sub_start))

        self.release_isa_reg()  # vis_gpr_ret
        self.release_isa_reg()  # vis_gpr_bucket
        self.release_isa_reg()  # vis_ln_chunks
        self.release_isa_reg()  # vis_S_reg
        self.stop_capture()

        all_bytes = bytearray()
        for inst in self.capture_buffer:
            all_bytes.extend(inst.get_bytes())
        program_addr = self.get_program_dram_addr()
        self._dma_write_retry(DMA_DEVICE_H2C, program_addr, all_bytes, len(all_bytes))
        self.allocate_program_dram(len(all_bytes))
        self.clear_capture_buffer()
        self._vis_program_addr = program_addr
        print(f"    Vision encoder compiled: {len(all_bytes)} bytes at 0x{program_addr:X}")
        return program_addr

    # =========================================================================
    # Action-expert (Gemma-300M) flow-matching denoising stack.
    #
    # Ported from pi05_torch_ref.py: ada_rms_norm / gated_mlp / sincos_pos_embed /
    # joint_attention(suf_tokens branch) / suffix_step / the Euler loop in run_pi05.
    #
    # Geometry (manifest hw_notes): 18 layers, hidden=1024, heads=8, kv_heads=1,
    # head_dim=256 (== self.HEAD_DIM, shared with the prefix Gemma-2B geometry --
    # self.identity_addr from tensor_init() is already sized for this head_dim).
    # intermediate=4096. All multiples of 64: no padding needed on those dims.
    #
    # ASSUMED PREFIX KV-CACHE INTERFACE (not finalized by the prefix agent at the
    # time this was written -- reconcile before running end-to-end):
    #   self.PREFIX_SEQ_LEN            -- int, padded prefix token count (manifest: 1024)
    #   self.prefix_k_cache_addr[l]    -- DRAM base for layer l's cached K, shape
    #                                      (PREFIX_SEQ_LEN, HEAD_DIM) bf16, kv_heads=1 (MQA)
    #   self.prefix_v_cache_addr[l]    -- same for V
    # If those attributes are missing, tensor_init_action_expert() below allocates
    # a zero-filled placeholder buffer per layer so compile still runs; real prefix
    # KV must be DMA'd into that placeholder (or the attrs pointed at the prefix
    # agent's real buffers) before this is numerically correct.
    # =========================================================================
    AE_HIDDEN = 1024
    AE_INTERMEDIATE = 4096
    AE_LAYERS = 18
    AE_HEADS = 8
    AE_KV_HEADS = 1
    AE_ACTION_DIM_PADDED = 32
    AE_XT_WIDTH = 64  # physical width of x_t/v_t buffers (action_dim 32 padded to 64-align)
    AE_ACTION_HORIZON = 10
    AE_ACTION_HORIZON_PADDED = 64  # padded for 64-alignment (flash / matmul row tiling)
    AE_NUM_DENOISE_STEPS = 10
    AE_LOOP_TRIP_OVERRIDE = None  # debug knob, see compile_denoise_loop's loop_start call
    DENOISE_STEP0_PROBE = False  # if True, snapshot step-0 intermediates for reference diff

    # ---- action-expert weights ---------------------------------------------
    def weight_init_action_expert(self):
        """Load action-expert (Gemma-300M) weights from weights_export/*.npy into
        params DRAM. Additive to weight_init(): hooked in via the hasattr() check
        in weight_init() above, does not touch the prefix/vision weight loading
        owned by the other two agents.

        Quantization policy: all matmul weight matrices (action_in_proj,
        time_mlp_in/out, action_out_proj, q/kv/attn_vec einsum, mlp gating/linear,
        and the AdaRMSNorm conditioning Dense_0 kernels) are IF4 (q4_64) via
        quantize_q4_64 + store_quantized_weight. Biases and norm terms stay bf16
        via store_weight. AdaRMSNorm itself has no learned gamma (plain RMSNorm);
        only its conditioning Dense layer has a kernel+bias.

        Weight layout note: weights_export tensors are JAX-style (in_features,
        out_features) i.e. consumed as ``x @ W``. The engine's matmat_mul_core
        computes ``A @ B^T`` with B stored (N, K) = (out, in). Every matmul
        weight is therefore transposed (last two dims) before quantizing/storing.
        """
        wdir = os.path.join(self.script_dir, "weights_export")
        manifest_path = os.path.join(wdir, "manifest.json")
        with open(manifest_path) as f:
            wman = json.load(f)

        def _load(name):
            info = wman[name]
            arr = np.load(os.path.join(wdir, info["file"]))
            return torch.from_numpy(arr.astype(np.float32))

        def _store_matmul(name):
            """Load (..., K, N) JAX-layout weight, transpose last two dims ->
            (..., N, K), quantize to IF4, store. Returns (scale_addr, data_addr)."""
            w = _load(name).transpose(-1, -2).contiguous().to(torch.bfloat16)
            data, _ = _mlc_quantize_q4_64(w)
            return store_quantized_weight(self, data.tobytes())

        def _store_bf16(name):
            return store_weight(self, _load(name).to(torch.bfloat16))

        def _store_matmul_npad(name, n_pad):
            """Like _store_matmul, but zero-pads the N (output) dim up to n_pad.
            Used for action_out_proj: output action_dim=32 padded to 64 so v_t is
            physically 64-wide, matching the 64-wide x_t buffer -- lets the euler
            update and action_in_proj run as plain contiguous ops (no strided
            32->64 staging, which was reading noise rows at 2x stride)."""
            w = _load(name).transpose(-1, -2).contiguous()  # (N_real, K)
            n_real = w.shape[-2]
            if n_real < n_pad:
                w = torch.nn.functional.pad(w, (0, 0, 0, n_pad - n_real))  # pad dim -2 (N)
            w = w.to(torch.bfloat16)
            data, _ = _mlc_quantize_q4_64(w)
            return store_quantized_weight(self, data.tobytes())

        def _store_bf16_npad(name, n_pad):
            t = _load(name)  # (N_real,)
            if t.shape[-1] < n_pad:
                t = torch.nn.functional.pad(t, (0, n_pad - t.shape[-1]))
            return store_weight(self, t.to(torch.bfloat16))

        def _store_matmul_kpad(name, k_pad):
            """Like _store_matmul, but zero-pads the K (reduction) dim up to
            k_pad. Needed for action_in_proj: real action_dim=32 < the
            engine's matmat_mul_core K%64==0 requirement (also the IF4
            block_size=64 boundary)."""
            w = _load(name).transpose(-1, -2).contiguous()  # (N, K_real)
            k_real = w.shape[-1]
            if k_real < k_pad:
                w = torch.nn.functional.pad(w, (0, k_pad - k_real))
            w = w.to(torch.bfloat16)
            data, _ = _mlc_quantize_q4_64(w)
            return store_quantized_weight(self, data.tobytes())

        # --- flow-matching I/O projections + timestep MLP (not per-layer) ---
        # action_in_proj: K=action_dim=32 padded to 64 (matmat_mul_core requires
        # K % UE_VECTOR_SIZE(64) == 0); the caller (compile_denoise_loop) zero-pads
        # AE_XT_DRAM into AE_XT_PAD_DRAM (S, 64) to match.
        self.ae_action_in_scale, self.ae_action_in_data = _store_matmul_kpad("action_in_proj.kernel", 64)
        self.ae_action_in_bias = _store_bf16("action_in_proj.bias")
        self.ae_time_in_scale, self.ae_time_in_data = _store_matmul("time_mlp_in.kernel")
        self.ae_time_in_bias = _store_bf16("time_mlp_in.bias")
        self.ae_time_out_scale, self.ae_time_out_data = _store_matmul("time_mlp_out.kernel")
        self.ae_time_out_bias = _store_bf16("time_mlp_out.bias")
        # action_out_proj output N padded 32->64 so v_t is physically 64-wide
        # (matches the 64-wide x_t buffer -> plain contiguous euler + no staging).
        self.ae_action_out_scale, self.ae_action_out_data = _store_matmul_npad("action_out_proj.kernel", 64)
        self.ae_action_out_bias = _store_bf16_npad("action_out_proj.bias", 64)

        # --- per-layer action-expert transformer weights ---------------------
        self.ae_layer_addrs = []
        for layer in range(self.AE_LAYERS):
            la = {}

            def _store_matmul_layer(name, sl):
                w = _load(name)[sl].transpose(-1, -2).contiguous().to(torch.bfloat16)
                data, _ = _mlc_quantize_q4_64(w)
                return store_quantized_weight(self, data.tobytes())

            # AdaRMSNorm conditioning: Dense_0 (1024 -> 3*1024=3072), kernel quantized,
            # bias stays bf16.
            la["pre_attn_norm_dense_scale"], la["pre_attn_norm_dense_data"] = \
                _store_matmul_layer("PaliGemma.llm.layers.pre_attention_norm_1.Dense_0.kernel", layer)
            la["pre_attn_norm_dense_bias"] = store_weight(
                self, _load("PaliGemma.llm.layers.pre_attention_norm_1.Dense_0.bias")[layer].to(torch.bfloat16))
            la["pre_ffw_norm_dense_scale"], la["pre_ffw_norm_dense_data"] = \
                _store_matmul_layer("PaliGemma.llm.layers.pre_ffw_norm_1.Dense_0.kernel", layer)
            la["pre_ffw_norm_dense_bias"] = store_weight(
                self, _load("PaliGemma.llm.layers.pre_ffw_norm_1.Dense_0.bias")[layer].to(torch.bfloat16))

            # Attention: per-head Q (8, 1024, 256), shared single-head KV (1, 1024, 256), O (8, 256, 1024)
            q_all = _load("PaliGemma.llm.layers.attn.q_einsum_1.w")[layer]     # (8, 1024, 256)
            kv_all = _load("PaliGemma.llm.layers.attn.kv_einsum_1.w")[layer]   # (2, 1, 1024, 256)
            o_all = _load("PaliGemma.llm.layers.attn.attn_vec_einsum_1.w")[layer]  # (8, 256, 1024)
            la["q_scale"], la["q_data"] = [], []
            la["o_scale"], la["o_data"] = [], []
            for h in range(self.AE_HEADS):
                qw = q_all[h].transpose(-1, -2).contiguous().to(torch.bfloat16)  # (256,1024) N,K
                data, _ = _mlc_quantize_q4_64(qw)
                sa, da = store_quantized_weight(self, data.tobytes())
                la["q_scale"].append(sa); la["q_data"].append(da)
                ow = o_all[h].transpose(-1, -2).contiguous().to(torch.bfloat16)  # (1024,256) N,K
                data, _ = _mlc_quantize_q4_64(ow)
                sa, da = store_quantized_weight(self, data.tobytes())
                la["o_scale"].append(sa); la["o_data"].append(da)
            kw = kv_all[0, 0].transpose(-1, -2).contiguous().to(torch.bfloat16)  # (256,1024) N,K
            data, _ = _mlc_quantize_q4_64(kw)
            la["k_scale"], la["k_data"] = store_quantized_weight(self, data.tobytes())
            vw = kv_all[1, 0].transpose(-1, -2).contiguous().to(torch.bfloat16)
            data, _ = _mlc_quantize_q4_64(vw)
            la["v_scale"], la["v_data"] = store_quantized_weight(self, data.tobytes())

            # Gated MLP: gating_einsum (2, 1024, 4096) -> [gate_w, up_w], linear (4096, 1024)
            gating = _load("PaliGemma.llm.layers.mlp_1.gating_einsum")[layer]  # (2,1024,4096)
            gate_w = gating[0].transpose(-1, -2).contiguous().to(torch.bfloat16)  # (4096,1024) N,K
            data, _ = _mlc_quantize_q4_64(gate_w)
            la["mlp_gate_scale"], la["mlp_gate_data"] = store_quantized_weight(self, data.tobytes())
            up_w = gating[1].transpose(-1, -2).contiguous().to(torch.bfloat16)
            data, _ = _mlc_quantize_q4_64(up_w)
            la["mlp_up_scale"], la["mlp_up_data"] = store_quantized_weight(self, data.tobytes())
            la["mlp_down_scale"], la["mlp_down_data"] = \
                _store_matmul_layer("PaliGemma.llm.layers.mlp_1.linear", layer)

            self.ae_layer_addrs.append(la)

        # --- final AdaRMSNorm (applied after all 18 layers, before action_out_proj) ---
        self.ae_final_norm_dense_scale, self.ae_final_norm_dense_data = \
            _store_matmul("PaliGemma.llm.final_norm_1.Dense_0.kernel")
        self.ae_final_norm_dense_bias = _store_bf16("PaliGemma.llm.final_norm_1.Dense_0.bias")

        print(f"weight_init_action_expert done; params DRAM at 0x{self.get_params_dram_addr():X}")

    # ---- action-expert scratch tensors --------------------------------------
    def tensor_init_action_expert(self):
        """Allocate action-expert activation/attention scratch DRAM. Sizes use
        AE_ACTION_HORIZON_PADDED (S=64) for the suffix block and self.PREFIX_SEQ_LEN
        (P) for the cached prefix length -- see the ASSUMED KV-CACHE INTERFACE
        comment above compile_suffix_step for the P source."""
        bpe = 2
        H, I, D = self.AE_HIDDEN, self.AE_INTERMEDIATE, self.HEAD_DIM
        S = self.AE_ACTION_HORIZON_PADDED
        P = getattr(self, "PREFIX_SEQ_LEN", 1024)
        self.AE_PREFIX_SEQ_LEN = P
        Tkv = P + S
        self.AE_TKV = Tkv

        # Combined per-layer K/V (prefix rows [0:P] + this-step suffix rows [P:P+S]).
        # kv_heads=1 (MQA): single (Tkv, D) buffer per layer, reused across all 10
        # Euler steps (prefix rows copied once at init; suffix rows overwritten/step).
        self.AE_KV_LAYER_STRIDE = Tkv * D * bpe
        self.ae_k_combined = [self.allocate_tensor_dram(self.AE_KV_LAYER_STRIDE) for _ in range(self.AE_LAYERS)]
        self.ae_v_combined = [self.allocate_tensor_dram(self.AE_KV_LAYER_STRIDE) for _ in range(self.AE_LAYERS)]

        # Q buffer: (heads, Tkv, D) -- only rows [0:S] per head are real suffix
        # queries; rows [S:Tkv] are padding so prefill_flash_attention_core (which
        # assumes Q/K share the same seq_len) can run Q against the full Tkv K/V.
        # Only the first S output rows are read back.
        self.AE_Q_DRAM = self.allocate_tensor_dram(self.AE_HEADS * Tkv * D * bpe)
        zero_ae_q = torch.zeros(self.AE_HEADS * Tkv, D, dtype=torch.bfloat16)
        self.dma_write(DMA_DEVICE_H2C, self.AE_Q_DRAM, zero_ae_q.contiguous(), self.AE_HEADS * Tkv * D * bpe)
        self.AE_ATTN_OUT_DRAM = self.allocate_tensor_dram(self.AE_HEADS * Tkv * D * bpe)
        self.AE_ATTN_SCRATCH_DRAM = self.allocate_tensor_dram((D * Tkv + max(D, 64) * Tkv) * bpe)
        self.AE_ATTN_RESULT_DRAM = self.allocate_tensor_dram(S * H * bpe)  # un-headed (S,H) post-o-proj input
        self.AE_O_PROJ_DRAM = self.allocate_tensor_dram(S * H * bpe)

        # Shared-subroutine flash attention (same fix as compile_prefix): one flash
        # body compiled ONCE in compile_denoise_loop (after all 180 layer-step
        # bodies) and jumped to from every (step, layer, head) call site -- 1440
        # jumps into one body, instead of prefill_flash_attention_core statically
        # re-emitting a full Tkv~1088 attention body 180 times, which blew the
        # compiled denoise program up near the 4GB DRAM ceiling. K/V need per-layer
        # (not per-head) marshalling here since each layer has its own
        # ae_k_combined/ae_v_combined buffer (unlike prefix's one fixed buffer) --
        # copied into this fixed scratch once per (step,layer), reused for all 8
        # heads' jumps within that layer.
        self.AE_FLASH_Q_DRAM = self.allocate_tensor_dram(Tkv * D * bpe)
        zero_ae_flash_q = torch.zeros(Tkv, D, dtype=torch.bfloat16)
        self.dma_write(DMA_DEVICE_H2C, self.AE_FLASH_Q_DRAM, zero_ae_flash_q.contiguous(), Tkv * D * bpe)
        self.AE_FLASH_K_DRAM = self.allocate_tensor_dram(Tkv * D * bpe)
        self.AE_FLASH_V_DRAM = self.allocate_tensor_dram(Tkv * D * bpe)
        self.AE_FLASH_OUT_DRAM = self.allocate_tensor_dram(Tkv * D * bpe)
        self.AE_FLASH_ATTN_P_DRAM = self.allocate_tensor_dram(Tkv * Tkv * bpe)

        # Suffix attention bias: (Tkv, Tkv) additive bf16, 0 for valid prefix+suffix
        # cols (bidirectional per pi0.5 ar_mask all-False), large-negative for the
        # [S:Tkv] padding columns/rows (unused rows are never read back, but the
        # columns feeding real rows' softmax must be masked so padding K/V garbage
        # doesn't pollute attention over rows [0:S]), AND large-negative for
        # [valid_len:P] -- the prefix's OWN internal padding-token columns (compile_prefix
        # pads seq_len=P=832 but only the first valid_len~784-813 rows are real tokens;
        # rows [valid_len:P] hold finite-but-meaningless padding-token K/V that must not
        # leak into the suffix's cross-attention softmax over the real S=64 action rows).
        # Previously unmasked -- a real accuracy bug (not a NaN source), fixed here.
        NEG_INF = -1e9
        valid_len = getattr(self, "prefix_valid_len", P)
        bias = torch.zeros(Tkv, Tkv, dtype=torch.bfloat16)
        bias[:, P + S:] = NEG_INF   # no such columns (P+S==Tkv) -- kept for clarity/symmetry
        if valid_len < P:
            bias[:, valid_len:P] = NEG_INF
        bias[S:, :] = 0.0           # unused query rows; value irrelevant, never read back
        self.AE_BIAS_DRAM = self.get_params_dram_addr()
        self.dma_write(DMA_DEVICE_H2C, self.AE_BIAS_DRAM, bias.contiguous(), Tkv * Tkv * bpe)
        self.allocate_params_dram(Tkv * Tkv * bpe)

        # x / norm / adarms scratch (S, H)
        self.AE_X_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.AE_NORM_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.AE_ATTN_GATED_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.AE_ADARMS_MUL_SCRATCH_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.AE_RESIDUAL_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.AE_MLP_GATE_DRAM = self.allocate_tensor_dram(S * I * bpe)
        self.AE_MLP_UP_DRAM = self.allocate_tensor_dram(S * I * bpe)
        self.AE_MLP_MULT_DRAM = self.allocate_tensor_dram(S * I * bpe)
        self.AE_MLP_DOWN_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.AE_MLP_GATED_DRAM = self.allocate_tensor_dram(S * H * bpe)

        # adarms conditioning scratch: modulation (1, 3*H), and its 3 broadcast-to-S copies
        self.AE_COND_DRAM = self.allocate_tensor_dram(1 * H * bpe)               # timestep embedding, (1,H)
        self.AE_MODULATION_DRAM = self.allocate_tensor_dram(1 * 3 * H * bpe)     # (1, 3H) = [scale,shift,gate]
        self.AE_SCALE_BCAST_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.AE_SHIFT_BCAST_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.AE_GATE_BCAST_DRAM = self.allocate_tensor_dram(S * H * bpe)

        # timestep embedding scratch (sincos -> time_mlp_in -> silu -> time_mlp_out -> silu)
        self.AE_SINCOS_DRAM = self.allocate_tensor_dram(1 * H * bpe)
        self.AE_TIME_HIDDEN_DRAM = self.allocate_tensor_dram(1 * H * bpe)

        # all-ones gamma constant: rms_norm_core multiplies by gamma directly (no
        # implicit +1, unlike gemma3's pre-offset convention), so AdaRMSNorm's
        # plain (no learned scale) RMSNorm needs gamma=1 rather than gamma=None
        # (rms_norm_core_dram_legacy dereferences GAMMA_DRAM_ADDR unconditionally).
        self.AE_ONES_DRAM = self.get_params_dram_addr()
        self.dma_write(DMA_DEVICE_H2C, self.AE_ONES_DRAM, torch.ones(H, dtype=torch.bfloat16).contiguous(), H * bpe)
        self.allocate_params_dram(H * bpe)

        # action tokens (x_t projected through action_in_proj) and the denoise state.
        # x_t/v_t are physically AE_XT_WIDTH(64)-wide (real action_dim 32 in cols
        # [0:32], cols [32:64] held at 0). Storing x_t already 64-wide lets
        # action_in_proj read it CONTIGUOUSLY (K=64) with no 32->64 strided
        # staging -- that staging was reading noise rows at 2x stride (bug).
        XW = self.AE_XT_WIDTH
        self.AE_ACTION_TOK_DRAM = self.allocate_tensor_dram(S * H * bpe)
        self.AE_XT_DRAM = self.allocate_tensor_dram(S * XW * bpe)
        self.AE_VT_DRAM = self.allocate_tensor_dram(S * XW * bpe)
        # Per-step x_t snapshots (probe_nan_report): AE_XT_DRAM is overwritten in
        # place every step, so only the LAST step's value survives a full run --
        # copy each step's post-euler-update x_t to its own dedicated slot too,
        # so one post-run readback can NaN-check every step at once.
        self.AE_STEP_SNAPSHOT_DRAM = [self.allocate_tensor_dram(S * XW * bpe)
                                       for _ in range(self.AE_NUM_DENOISE_STEPS)]

        # Prefix KV cache placeholder, only used if the prefix agent hasn't wired
        # self.prefix_k/v_cache_addr yet (see ASSUMED PREFIX KV-CACHE INTERFACE).
        if not hasattr(self, "prefix_k_cache_addr"):
            print("[ae] WARNING: self.prefix_k_cache_addr not found -- allocating a "
                  "zero placeholder. Point this at the real prefix KV cache before "
                  "trusting suffix-attention numerics.")
            zero_row = torch.zeros(P, D, dtype=torch.bfloat16)
            self.prefix_k_cache_addr = []
            self.prefix_v_cache_addr = []
            for _ in range(self.AE_LAYERS):
                kaddr = self.get_params_dram_addr()
                self.dma_write(DMA_DEVICE_H2C, kaddr, zero_row.contiguous(), P * D * bpe)
                self.allocate_params_dram(P * D * bpe)
                vaddr = self.get_params_dram_addr()
                self.dma_write(DMA_DEVICE_H2C, vaddr, zero_row.contiguous(), P * D * bpe)
                self.allocate_params_dram(P * D * bpe)
                self.prefix_k_cache_addr.append(kaddr)
                self.prefix_v_cache_addr.append(vaddr)

        # NOTE: the combined K/V buffers' prefix rows [0:P] are seeded by
        # compile_denoise_loop() itself (as the first thing it captures), NOT
        # here -- this method only allocates DRAM and runs before any capture
        # session is open (or after the prefix one was already closed+cleared
        # by _compile_and_run), so instructions emitted here would just get
        # silently discarded the moment compile_denoise_loop's start_capture()
        # resets capture_buffer=[]. That was a real bug: ae_k_combined/
        # ae_v_combined's prefix rows never actually got written on hardware,
        # leaving stale/garbage DRAM content that fed straight into the first
        # suffix layer's attention and NaN'd immediately.
        # Step-0 probe snapshot buffers (allocated LAST so they can't shift the
        # addresses of any critical AE buffer -- address layout is load-bearing
        # here, see the DRAM-layout NaN bug). Each holds one step-0 intermediate
        # so a post-run readback can diff it against the torch reference and
        # localize which action-expert op first diverges.
        if self.DENOISE_STEP0_PROBE:
            self.AE_P0_ACTION_IN = self.allocate_tensor_dram(S * H * bpe)   # action_in_proj out (S,H)
            self.AE_P0_TIME_EMB  = self.allocate_tensor_dram(1 * H * bpe)   # time embed (1,H)
            self.AE_P0_SUF_L0    = self.allocate_tensor_dram(S * H * bpe)   # suffix layer0 out (S,H)
            self.AE_P0_SUF_L17   = self.allocate_tensor_dram(S * H * bpe)   # suffix layer17 out (S,H)
            self.AE_P0_VT        = self.allocate_tensor_dram(S * self.AE_XT_WIDTH * bpe)  # v_t (S,64)
            self.AE_P0_XT_PAD    = self.allocate_tensor_dram(S * self.AE_XT_WIDTH * bpe)  # x_t (S,64) fed to action_in_proj
            self.AE_P0_L0_NORM   = self.allocate_tensor_dram(S * H * bpe)   # layer0 pre-attn AdaRMSNorm out
            self.AE_P0_L0_ATTN   = self.allocate_tensor_dram(S * H * bpe)   # layer0 attention o-proj out
            self.AE_P0_L0_RESID  = self.allocate_tensor_dram(S * H * bpe)   # layer0 post-attn residual
        print(f"tensor_init_action_expert done; tensor DRAM at 0x{self.get_tensor_dram_addr():X}")

    # ---- small helpers --------------------------------------------------
    def _ae_broadcast_row(self, src_dram, dst_dram, rows, width):
        """Copy a single (1, width) bf16 row from src_dram to `rows` contiguous
        rows at dst_dram (broadcast across the row/batch dim -- used for AdaRMSNorm
        scale/shift/gate and the sincos/timestep conditioning vector)."""
        bpe = 2
        self.accelerator_memory_to_sram(src_dram, 0x00000, width)
        for r in range(rows):
            self.sram_to_accelerator_memory(0x00000, dst_dram + r * width * bpe, width)

    def _ae_matmul(self, M, K, N, A, scale_addr, data_addr, OUT, bias_addr=None, gpr_M_reg=None, **kw):
        """IF4 (q4_64) quantized matmul, per the quantization policy in
        weight_init_action_expert. Pass gpr_M_reg (primed with M via ADD_SET by
        the caller) to compile a compact PBI runtime loop instead of static-M
        unrolling -- required here because this body is itself repeated 180x
        (10 Euler steps x 18 layers); static-M was blowing the compiled program
        up to the point compilation didn't finish in 900s (see compile_prefix's
        identical fix for the root-cause writeup)."""
        self.matmat_mul_core(M=M, K=K, N=N, A_DRAM_ADDR=A, B_DRAM_ADDR=data_addr,
                              OUTPUT_DRAM_ADDR=OUT, is_B_quantized=True, data_type=TYPE.IF4,
                              SCALE_DRAM_ADDR=scale_addr, C_DRAM_ADDR=bias_addr, gpr_M_reg=gpr_M_reg, **kw)

    def _ae_ada_rms_norm(self, M, x_dram, dense_scale, dense_data, dense_bias,
                          norm_out_dram, gate_bcast_dram, apply_gate=True, gpr_M_reg=None):
        """AdaRMSNorm: plain RMSNorm (no gamma) on x, then a conditioning Dense
        (cond(1,1024) -> (1,3*1024)) split into scale/shift/gate, broadcast over
        the M suffix rows, applied as normed*(1+scale)+shift. Writes the gate
        broadcast to gate_bcast_dram for the caller to apply after attn/mlp.
        gpr_M_reg (primed with M) makes the RMSNorm's row loop a runtime PBI
        loop -- see _ae_matmul's docstring for why this matters here."""
        H = self.AE_HIDDEN
        bpe = 2
        # 1. RMSNorm (no gamma)
        self.rms_norm_core_dram(M=M, N=H, A_DRAM_ADDR=x_dram, OUTPUT_DRAM_ADDR=self.AE_NORM_DRAM,
                                 GAMMA_DRAM_ADDR=self.AE_ONES_DRAM, gpr_M_reg=gpr_M_reg)
        # 2. conditioning matmul: cond (1,H) @ dense (H,3H) -> modulation (1,3H), +bias
        # (M=1 here always -- one conditioning vector regardless of the caller's M -- so
        # no gpr_M_reg needed, a single-row matmul is already minimal.)
        self._ae_matmul(1, H, 3 * H, self.AE_COND_DRAM, dense_scale, dense_data,
                         self.AE_MODULATION_DRAM, bias_addr=dense_bias)
        # 3. split scale/shift/gate (each H wide) and broadcast each to M rows
        scale_addr = self.AE_MODULATION_DRAM
        shift_addr = self.AE_MODULATION_DRAM + H * bpe
        gate_addr = self.AE_MODULATION_DRAM + 2 * H * bpe
        self._ae_broadcast_row(scale_addr, self.AE_SCALE_BCAST_DRAM, M, H)
        self._ae_broadcast_row(shift_addr, self.AE_SHIFT_BCAST_DRAM, M, H)
        if apply_gate:
            self._ae_broadcast_row(gate_addr, gate_bcast_dram, M, H)
        # 4. (1 + scale) -- add 1.0 to the broadcast scale buffer in place
        self.accelerator_memory_to_sram(self.AE_SCALE_BCAST_DRAM, 0x00000, M * H)
        self.broadcast_add(scalar=1.0, sram_start_addr=0x00000, sram_wb_addr=0x00000, element_size=M * H)
        self.sram_to_accelerator_memory(0x00000, self.AE_SCALE_BCAST_DRAM, M * H)
        # 5. out = normed * (1+scale) + shift; route through dedicated scratch buffer
        # to avoid the hardware read/write hazard from aliasing an input with the
        # output in one DMA-backed elementwise op (same class as the confirmed hang
        # trigger fixed in compile_prefix -- see that function's comment).
        eltwise_mul_core_dram(self, size=M * H, A_DRAM_ADDR=self.AE_NORM_DRAM,
                               B_DRAM_ADDR=self.AE_SCALE_BCAST_DRAM, OUTPUT_DRAM_ADDR=self.AE_ADARMS_MUL_SCRATCH_DRAM)
        eltwise_add_core_dram(self, size=M * H, A_DRAM_ADDR=self.AE_ADARMS_MUL_SCRATCH_DRAM,
                               B_DRAM_ADDR=self.AE_SHIFT_BCAST_DRAM, OUTPUT_DRAM_ADDR=norm_out_dram)

    def _ae_gated_mlp(self, M, x_dram, la, out_dram, gpr_M_reg=None):
        """Gated MLP: gate=x@gate_w (gelu), up=x@up_w, out=(gate*up)@linear. Uses
        matmat_mul_core's gelu_enable fused activation on the gate branch, per the
        torch reference `F.gelu(x @ gate_w, approximate="none")`."""
        H, I = self.AE_HIDDEN, self.AE_INTERMEDIATE
        self._ae_matmul(M, H, I, x_dram, la["mlp_gate_scale"], la["mlp_gate_data"],
                         self.AE_MLP_GATE_DRAM, gelu_enable=True, gpr_M_reg=gpr_M_reg)
        self._ae_matmul(M, H, I, x_dram, la["mlp_up_scale"], la["mlp_up_data"], self.AE_MLP_UP_DRAM, gpr_M_reg=gpr_M_reg)
        eltwise_mul_core_dram(self, size=M * I, A_DRAM_ADDR=self.AE_MLP_GATE_DRAM,
                               B_DRAM_ADDR=self.AE_MLP_UP_DRAM, OUTPUT_DRAM_ADDR=self.AE_MLP_MULT_DRAM)
        self._ae_matmul(M, I, H, self.AE_MLP_MULT_DRAM, la["mlp_down_scale"], la["mlp_down_data"], out_dram, gpr_M_reg=gpr_M_reg)

    def _ae_sincos_time_embed(self, t_scalar):
        """Host-computed sincos timestep embedding (dim=AE_HIDDEN, matches
        sincos_pos_embed in pi05_torch_ref.py) DMA'd to AE_SINCOS_DRAM, then
        time_mlp_in -> silu -> time_mlp_out -> silu -> AE_COND_DRAM (the AdaRMSNorm
        conditioning vector for this Euler step).

        Only used by the legacy fully-unrolled path (kept for reference/tests).
        compile_denoise_loop itself uses the table + runtime-address variant
        below (_ae_build_sincos_table / _ae_time_embed_from_table) so the whole
        10-step Euler loop can be a single compiled body run via a real
        hardware loop_start/loop_end instead of 10 statically unrolled copies."""
        H = self.AE_HIDDEN
        min_period, max_period = 4e-3, 4.0
        frac = torch.linspace(0.0, 1.0, H // 2)
        period = min_period * (max_period / min_period) ** frac
        sinusoid = t_scalar * (1.0 / period) * 2 * math.pi
        emb = torch.cat([torch.sin(sinusoid), torch.cos(sinusoid)]).to(torch.bfloat16)
        self.dma_write(DMA_DEVICE_H2C, self.AE_SINCOS_DRAM, emb.contiguous(), H * 2)

        self._ae_matmul(1, H, H, self.AE_SINCOS_DRAM, self.ae_time_in_scale, self.ae_time_in_data,
                         self.AE_TIME_HIDDEN_DRAM, bias_addr=self.ae_time_in_bias, silu_enable=True)
        self._ae_matmul(1, H, H, self.AE_TIME_HIDDEN_DRAM, self.ae_time_out_scale, self.ae_time_out_data,
                         self.AE_COND_DRAM, bias_addr=self.ae_time_out_bias, silu_enable=True)

    def _ae_build_sincos_table(self):
        """Host-precompute all AE_NUM_DENOISE_STEPS sincos timestep embeddings
        (t = 1.0, 0.9, ..., 0.1 -- matches the Euler loop's t=1.0, dt=-1/N
        schedule) as one contiguous (N, AE_HIDDEN) bf16 table in DRAM. Lets the
        runtime loop body read the correct row via a GPR-held address instead
        of a fresh host DMA write per step (which would require re-running
        Python between hardware loop iterations -- impossible)."""
        H = self.AE_HIDDEN
        N = self.AE_NUM_DENOISE_STEPS
        min_period, max_period = 4e-3, 4.0
        frac = torch.linspace(0.0, 1.0, H // 2)
        period = min_period * (max_period / min_period) ** frac
        dt = -1.0 / N
        rows = []
        t = 1.0
        for _ in range(N):
            sinusoid = t * (1.0 / period) * 2 * math.pi
            rows.append(torch.cat([torch.sin(sinusoid), torch.cos(sinusoid)]))
            t += dt
        table = torch.stack(rows).to(torch.bfloat16).contiguous()  # (N, H)
        addr = self.get_params_dram_addr()
        self.dma_write(DMA_DEVICE_H2C, addr, table, N * H * 2)
        self.allocate_params_dram(N * H * 2)
        return addr

    def _ae_precompute_cond_table(self):
        """The AdaRMSNorm conditioning vector is INPUT-INDEPENDENT -- it depends
        only on t (fixed per Euler step). So sincos -> time_mlp_in -> silu ->
        time_mlp_out -> silu is a compile-time constant for all N steps. Compute
        the whole (N, H) cond table on the host (matching pi05_torch_ref exactly,
        IF4 weights + F.silu) and DMA it in, instead of running the time MLP +
        fused-silu on hardware (whose approximate silu was cratering time_embed
        to -6dB). Zero accuracy loss -- it's exact constants. Returns table addr."""
        import pi05_torch_ref as _ref
        H, N = self.AE_HIDDEN, self.AE_NUM_DENOISE_STEPS
        min_period, max_period = 4e-3, 4.0
        frac = torch.linspace(0.0, 1.0, H // 2)
        period = min_period * (max_period / min_period) ** frac
        # IF4-fake-quantize the time-MLP kernels the same way the reference does
        # (Weights.__getitem__ applies maybe_quantize to ".kernel" tensors).
        Win  = _ref.maybe_quantize(self._npy("time_mlp_in.kernel").to(torch.bfloat16), "if4").float()
        bin_ = self._npy("time_mlp_in.bias").float()
        Wout = _ref.maybe_quantize(self._npy("time_mlp_out.kernel").to(torch.bfloat16), "if4").float()
        bout = self._npy("time_mlp_out.bias").float()
        dt = -1.0 / N
        rows = []
        t = 1.0
        for _ in range(N):
            sinusoid = t * (1.0 / period) * 2 * math.pi
            emb = torch.cat([torch.sin(sinusoid), torch.cos(sinusoid)]).to(torch.bfloat16).float()  # (H,)
            emb = torch.nn.functional.silu(emb @ Win + bin_)
            emb = torch.nn.functional.silu(emb @ Wout + bout)  # (H,) = AdaRMSNorm cond
            rows.append(emb)
            t += dt
        table = torch.stack(rows).to(torch.bfloat16).contiguous()  # (N, H)
        addr = self.get_params_dram_addr()
        self.dma_write(DMA_DEVICE_H2C, addr, table, N * H * 2)
        self.allocate_params_dram(N * H * 2)
        return addr

    def _ae_time_embed_from_table(self, addr_reg):
        """Runtime-loop-body version of _ae_sincos_time_embed: read the CURRENT
        row (address held in addr_reg, advanced by the caller each iteration)
        into AE_SINCOS_DRAM via general_reg_src, then the same time_mlp_in ->
        silu -> time_mlp_out -> silu -> AE_COND_DRAM chain as before."""
        H = self.AE_HIDDEN
        sram = 0x00000
        self.accelerator_memory_to_sram(0, sram, H, general_reg_src=addr_reg)
        self.sram_to_accelerator_memory(sram, self.AE_SINCOS_DRAM, H)

        self._ae_matmul(1, H, H, self.AE_SINCOS_DRAM, self.ae_time_in_scale, self.ae_time_in_data,
                         self.AE_TIME_HIDDEN_DRAM, bias_addr=self.ae_time_in_bias, silu_enable=True)
        self._ae_matmul(1, H, H, self.AE_TIME_HIDDEN_DRAM, self.ae_time_out_scale, self.ae_time_out_data,
                         self.AE_COND_DRAM, bias_addr=self.ae_time_out_bias, silu_enable=True)
        # advance to next step's row for the next loop iteration
        self.generate_instruction_add_imm(addr_reg, H * 2)

    # ---- one action-expert transformer layer (attention + gated MLP) --------
    def compile_suffix_step(self, layer_idx, x_in_dram, x_out_dram, gpr_M_reg=None, flash_ctx=None, step=None):
        """One action-expert layer body: AdaRMSNorm -> MQA attention (suffix Q vs
        combined prefix+suffix K/V) -> gated residual -> AdaRMSNorm -> gated MLP
        -> gated residual. Mirrors suffix_step()'s per-layer loop body in
        pi05_torch_ref.py (the `suf_tokens is not None` branch of joint_attention).
        gpr_M_reg (primed with S by the caller) makes every M=S matmul/RMSNorm in
        this body a compact PBI runtime loop -- this body is itself repeated 180x
        (10 Euler steps x 18 layers), so static-M unrolling blew the compiled
        program up past the point compilation could finish in any reasonable time.
        flash_ctx (dict from compile_denoise_loop): {prog_base, gpr_bucket, gpr_ret,
        call_sites} -- shared across all 180 calls; the flash body itself is
        compiled ONCE by the caller after every call site has been emitted."""
        la = self.ae_layer_addrs[layer_idx]
        H, D = self.AE_HIDDEN, self.HEAD_DIM
        S = self.AE_ACTION_HORIZON_PADDED
        Tkv, P = self.AE_TKV, self.AE_PREFIX_SEQ_LEN
        k_combined = self.ae_k_combined[layer_idx]
        v_combined = self.ae_v_combined[layer_idx]

        _pfx = f"step{step}_layer{layer_idx}" if step is not None else f"layer{layer_idx}"

        # 1. AdaRMSNorm (attention conditioning)
        self._ae_ada_rms_norm(S, x_in_dram, la["pre_attn_norm_dense_scale"], la["pre_attn_norm_dense_data"],
                               la["pre_attn_norm_dense_bias"], self.AE_NORM_DRAM, self.AE_GATE_BCAST_DRAM,
                               gpr_M_reg=gpr_M_reg)
        self._debug_op(f"{_pfx}_preattn_norm", self.AE_NORM_DRAM, S * H, shape=(S, H))
        self._debug_op(f"{_pfx}_attn_gate", self.AE_GATE_BCAST_DRAM, S * H, shape=(S, H))
        _p0l0 = self.DENOISE_STEP0_PROBE and step == 0 and layer_idx == 0
        if _p0l0:
            self._dram_copy(S * H * 2, self.AE_NORM_DRAM, self.AE_P0_L0_NORM)

        # 2. K/V projection for the suffix rows only -> combined buffer rows [P:P+S]
        self._ae_matmul(S, H, D, self.AE_NORM_DRAM, la["k_scale"], la["k_data"],
                         k_combined + P * D * 2, gpr_M_reg=gpr_M_reg)
        self._ae_matmul(S, H, D, self.AE_NORM_DRAM, la["v_scale"], la["v_data"],
                         v_combined + P * D * 2, gpr_M_reg=gpr_M_reg)
        self._debug_op(f"{_pfx}_kv_proj", k_combined + P * D * 2, S * D, shape=(S, D))

        # 3. Per-head Q projection into the (heads, Tkv, D) padded Q buffer (rows
        #    [0:S] real, [S:Tkv] unused/garbage -- see tensor_init_action_expert).
        head_bytes = Tkv * D * 2
        for h in range(self.AE_HEADS):
            self._ae_matmul(S, H, D, self.AE_NORM_DRAM, la["q_scale"][h], la["q_data"][h],
                             self.AE_Q_DRAM + h * head_bytes, gpr_M_reg=gpr_M_reg)
        self._debug_op(f"{_pfx}_q_proj", self.AE_Q_DRAM, S * D, shape=(S, D))

        # 4. MQA flash attention: Q (heads, Tkv, D) vs shared K/V (Tkv, D), additive
        #    bias (Tkv, Tkv). Only rows [0:S] of the output are meaningful.
        #    Per head: copy this layer's K/V (same for all 8 heads) + this head's
        #    Q into the fixed AE_FLASH_* scratch, jump into the shared subroutine,
        #    copy the result out to this head's slot in AE_ATTN_OUT_DRAM.
        self._dram_copy(Tkv * D * 2, k_combined, self.AE_FLASH_K_DRAM)
        self._dram_copy(Tkv * D * 2, v_combined, self.AE_FLASH_V_DRAM)
        self._debug_op(f"{_pfx}_flash_kv_staged", self.AE_FLASH_K_DRAM, Tkv * D, shape=(Tkv, D))
        for h in range(self.AE_HEADS):
            self._dram_copy(head_bytes, self.AE_Q_DRAM + h * head_bytes, self.AE_FLASH_Q_DRAM)
            self.generate_instruction_add_set(flash_ctx["gpr_bucket"], flash_ctx["num_buckets"])
            self.pad_capture_to_64b_boundary()
            return_word_addr = ue_35bit_addr_shifter(
                flash_ctx["prog_base"] + (self.capture_count + 2) * INSTRUCTION_SIZE_BYTES)
            self.generate_instruction_add_set(flash_ctx["gpr_ret"], return_word_addr)
            flash_ctx["call_sites"].append(self.capture_count)
            self.generate_instruction_jump_abs(target_instruction_word_addr=0)
            self._dram_copy(head_bytes, self.AE_FLASH_OUT_DRAM, self.AE_ATTN_OUT_DRAM + h * head_bytes)
        self._debug_op(f"{_pfx}_flash_attn_out", self.AE_ATTN_OUT_DRAM, S * D, shape=(S, D))

        # 5. un-stack heads' first S rows -> (S, heads*D) token-major, o-proj
        for h in range(self.AE_HEADS):
            self.accelerator_memory_to_sram(self.AE_ATTN_OUT_DRAM + h * head_bytes, 0x00000, S * D)
            # dest MUST start at this head's column block (h*D) in the (S, H)
            # token-major buffer -- without the +h*D*2 every head overwrites
            # cols [0:D] and o-proj reads stale/garbage for heads 1..7.
            self.sram_to_accelerator_memory(0x00000, self.AE_ATTN_RESULT_DRAM + h * D * 2, S * D,
                                             stride_bytes_per_chunk=D * 2, stride_jump_bytes=H * 2)
        # o projection is per-head (256,1024) -> accumulate into AE_O_PROJ_DRAM
        # via C_DRAM_ADDR-chained adds (first head writes, rest accumulate).
        for h in range(self.AE_HEADS):
            head_slice = self.AE_ATTN_RESULT_DRAM + h * D * 2
            self._ae_matmul(S, D, H, head_slice, la["o_scale"][h], la["o_data"][h],
                             self.AE_O_PROJ_DRAM, bias_addr=(self.AE_O_PROJ_DRAM if h > 0 else None),
                             gpr_M_reg=gpr_M_reg)
        self._debug_op(f"{_pfx}_o_proj", self.AE_O_PROJ_DRAM, S * H, shape=(S, H))
        if _p0l0:
            self._dram_copy(S * H * 2, self.AE_O_PROJ_DRAM, self.AE_P0_L0_ATTN)

        # 6. gated residual: x = x + gate * attn_out
        eltwise_mul_core_dram(self, size=S * H, A_DRAM_ADDR=self.AE_O_PROJ_DRAM,
                               B_DRAM_ADDR=self.AE_GATE_BCAST_DRAM, OUTPUT_DRAM_ADDR=self.AE_ATTN_GATED_DRAM)
        eltwise_add_core_dram(self, size=S * H, A_DRAM_ADDR=x_in_dram,
                               B_DRAM_ADDR=self.AE_ATTN_GATED_DRAM, OUTPUT_DRAM_ADDR=self.AE_RESIDUAL_DRAM)
        self._debug_op(f"{_pfx}_attn_residual", self.AE_RESIDUAL_DRAM, S * H, shape=(S, H))
        if _p0l0:
            self._dram_copy(S * H * 2, self.AE_RESIDUAL_DRAM, self.AE_P0_L0_RESID)

        # 7. AdaRMSNorm (mlp conditioning)
        self._ae_ada_rms_norm(S, self.AE_RESIDUAL_DRAM, la["pre_ffw_norm_dense_scale"],
                               la["pre_ffw_norm_dense_data"], la["pre_ffw_norm_dense_bias"],
                               self.AE_NORM_DRAM, self.AE_GATE_BCAST_DRAM, gpr_M_reg=gpr_M_reg)
        self._debug_op(f"{_pfx}_preffw_norm", self.AE_NORM_DRAM, S * H, shape=(S, H))

        # 8. gated MLP + gated residual
        self._ae_gated_mlp(S, self.AE_NORM_DRAM, la, self.AE_MLP_DOWN_DRAM, gpr_M_reg=gpr_M_reg)
        self._debug_op(f"{_pfx}_mlp_out", self.AE_MLP_DOWN_DRAM, S * H, shape=(S, H))
        eltwise_mul_core_dram(self, size=S * H, A_DRAM_ADDR=self.AE_MLP_DOWN_DRAM,
                               B_DRAM_ADDR=self.AE_GATE_BCAST_DRAM, OUTPUT_DRAM_ADDR=self.AE_MLP_GATED_DRAM)
        eltwise_add_core_dram(self, size=S * H, A_DRAM_ADDR=self.AE_RESIDUAL_DRAM,
                               B_DRAM_ADDR=self.AE_MLP_GATED_DRAM, OUTPUT_DRAM_ADDR=x_out_dram)

    # ---- full flow-matching denoising loop -----------------------------------
    def compile_denoise_loop(self):
        """10-step Euler integration (dt = -1/10, t: 1.0 -> 0.0), each step running
        action_in_proj -> timestep embed -> 18 action-expert layers -> final
        AdaRMSNorm -> action_out_proj -> x_t += dt * v_t. Mirrors the loop body in
        run_pi05() (pi05_torch_ref.py).

        Compiled ONCE as a single body wrapped in a real hardware loop_start/
        loop_end (runtime trip count = AE_NUM_DENOISE_STEPS), not 10 statically
        unrolled copies -- all 10 steps share identical dims/shapes (S, H, I,
        Tkv, NH), the only thing that varies per step is the scalar timestep
        t, which is now handled by precomputing all N sincos embeddings into
        one DRAM table (_ae_build_sincos_table) and reading the current row at
        runtime via a GPR-held address that advances each iteration
        (_ae_time_embed_from_table) -- a true hardware loop can't re-run host
        Python between iterations, so the old per-step host DMA write had to
        go. This also collapses the flash-attention shared-subroutine call
        sites from 1440 (10 x 18 x 8, one set per statically-unrolled step) down
        to 144 (18 x 8, one copy of the loop body), and the compiled
        instruction count by roughly the same ~10x.

        Every matmul/RMSNorm inside the loop body still runs through a PBI
        runtime M-loop (gpr_M_reg, primed once below) -- required independent
        of the outer step-loop change, since M=S rows per call still needs a
        runtime trip count to avoid static-M unrolling blowup within a single
        18-layer body.

        Assumes self.AE_XT_DRAM already holds the initial noise sample (S, 32) --
        caller (run harness) DMAs it in before invoking compile_denoise_loop(), or
        it defaults to whatever tensor_init_action_expert() left there (uninitialized).
        """
        S, H = self.AE_ACTION_HORIZON_PADDED, self.AE_HIDDEN
        dt = -1.0 / self.AE_NUM_DENOISE_STEPS
        t = 1.0

        self._debug_counter = 0
        self._debug_halt_info = None

        # THE denoise-NaN fix. alloc_isa_reg/alloc_inst_ptr use per-PROCESS
        # counters that start_capture() does NOT reset -- and any inner PBI op
        # in vision (27 layers) or prefix (18 layers) that leaks an allocation
        # drifts these counters upward. Without resetting them here, denoise's
        # ae_S_reg / flash gpr_bucket / PBI inst-pointers get DIFFERENT physical
        # indices in a full run (after vision+prefix) than in a --debug run
        # (denoise first), landing on reserved/stale regs -> 100% NaN, not a
        # crash. This is a PYTHON-allocator drift, which is why software_reset()
        # (hardware-only) did NOT fix it. mobilesam resets these counters at the
        # start of every stage for exactly this reason; pi05 never did.
        self.reset_isa_reg_counter()
        self.reset_inst_ptr_counter()

        ae_S_reg = self.alloc_isa_reg()
        self.generate_instruction_add_set(ae_S_reg, S)

        # Seed the combined K/V buffers' prefix rows [0:P] once (unchanged across
        # all 10 Euler steps / all layers' repeated suffix_step calls). MUST be
        # captured here (inside this function's own start_capture session) --
        # tensor_init_action_expert() runs too early (before any capture is
        # open, or after a prior one was already cleared) for instructions
        # emitted there to ever actually execute; see its docstring/comment.
        P, D = self.AE_PREFIX_SEQ_LEN, self.HEAD_DIM
        for layer in range(self.AE_LAYERS):
            self.accelerator_memory_to_sram(self.prefix_k_cache_addr[layer], 0x00000, P * D)
            self.sram_to_accelerator_memory(0x00000, self.ae_k_combined[layer], P * D)
            self.accelerator_memory_to_sram(self.prefix_v_cache_addr[layer], 0x00000, P * D)
            self.sram_to_accelerator_memory(0x00000, self.ae_v_combined[layer], P * D)

        # Shared-subroutine flash attention context, threaded into every
        # compile_suffix_step call across all 10 steps x 18 layers; the actual
        # subroutine body is compiled once, after the full loop below, and every
        # accumulated call site gets its jump patched to it (see compile_suffix_step
        # and tensor_init_action_expert's AE_FLASH_* buffers for the full rationale).
        #
        # REVERTED from a loop_start/loop_end runtime loop back to full static
        # unrolling (10 steps x 18 layers = 180 static layer bodies), matching
        # compile_prefix/compile_encoder's proven pattern exactly. The loop_start/
        # loop_end version compiled to a single small body (144 jump sites instead
        # of 1440) and a single Euler step ran clean standalone (loop_cnt=1, 12.4s),
        # but hung the instant a real backward branch was taken (loop_cnt=2+, and
        # the real loop_cnt=10) even after fixing a real found bug (loop_start()
        # not 64B-aligning its re-entry point before generate_instruction_jump_rela_jnz,
        # the only jump mode _generate_instruction_jump doesn't auto-align). That fix
        # didn't resolve the hang, and nobody in this codebase has ever combined
        # loop_start/loop_end with an internal shared-subroutine jump-and-return, so
        # this is unproven territory not worth continuing to debug blind. Static
        # unrolling only uses mechanisms already proven at scale this session.
        Tkv = self.AE_TKV
        flash_ctx = {
            "prog_base": self.get_program_dram_addr(),
            "gpr_bucket": self.alloc_isa_reg(),
            "gpr_ret": self.alloc_isa_reg(),
            "call_sites": [],
            "num_buckets": Tkv // UE_VECTOR_SIZE,
        }

        # Precompute the (N,H) AdaRMSNorm conditioning table on the host (exact
        # constants; replaces the HW time-MLP + approximate fused-silu).
        self.AE_COND_TABLE_DRAM = self._ae_precompute_cond_table()

        try:
            for step in range(self.AE_NUM_DENOISE_STEPS):
                # action_in_proj: x_t (S,64) -> action_tokens (S,H). x_t is already
                # physically 64-wide (cols [0:32] real, [32:64] zero), so the matmul
                # reads it CONTIGUOUSLY -- no 32->64 strided staging (which was
                # reading noise rows at 2x stride). action_in weight is K-padded 64.
                if self.DENOISE_STEP0_PROBE and step == 0:
                    self._dram_copy(S * self.AE_XT_WIDTH * 2, self.AE_XT_DRAM, self.AE_P0_XT_PAD)
                self._ae_matmul(S, self.AE_XT_WIDTH, H, self.AE_XT_DRAM,
                                 self.ae_action_in_scale, self.ae_action_in_data,
                                 self.AE_ACTION_TOK_DRAM, bias_addr=self.ae_action_in_bias, gpr_M_reg=ae_S_reg)
                self._debug_op(f"step{step}_action_in_proj", self.AE_ACTION_TOK_DRAM, S * H, shape=(S, H))
                if self.DENOISE_STEP0_PROBE and step == 0:
                    self._dram_copy(S * H * 2, self.AE_ACTION_TOK_DRAM, self.AE_P0_ACTION_IN)

                # timestep embedding -> AE_COND_DRAM (this step's AdaRMSNorm
                # conditioning): copy the precomputed constant row for this step
                # (host-exact) instead of running the HW time-MLP + fused silu.
                self._dram_copy(H * 2, self.AE_COND_TABLE_DRAM + step * H * 2, self.AE_COND_DRAM)
                self._debug_op(f"step{step}_time_embed", self.AE_COND_DRAM, H, shape=(1, H))
                if self.DENOISE_STEP0_PROBE and step == 0:
                    self._dram_copy(1 * H * 2, self.AE_COND_DRAM, self.AE_P0_TIME_EMB)

                # 18 action-expert layers
                x_cur = self.AE_ACTION_TOK_DRAM
                for layer_idx in range(self.AE_LAYERS):
                    x_next = self.AE_X_DRAM if x_cur is not self.AE_X_DRAM else self.AE_ACTION_TOK_DRAM
                    self.compile_suffix_step(layer_idx, x_cur, x_next, gpr_M_reg=ae_S_reg, flash_ctx=flash_ctx, step=step)
                    self._debug_op(f"step{step}_suffix_layer{layer_idx}", x_next, S * H, shape=(S, H))
                    if self.DENOISE_STEP0_PROBE and step == 0 and layer_idx == 0:
                        self._dram_copy(S * H * 2, x_next, self.AE_P0_SUF_L0)
                    if self.DENOISE_STEP0_PROBE and step == 0 and layer_idx == self.AE_LAYERS - 1:
                        self._dram_copy(S * H * 2, x_next, self.AE_P0_SUF_L17)
                    x_cur = x_next

                # final AdaRMSNorm (no gate applied -- action_out_proj consumes the
                # normed output directly, per the real bug noted in pi05_torch_ref.py)
                self._ae_ada_rms_norm(S, x_cur, self.ae_final_norm_dense_scale,
                                       self.ae_final_norm_dense_data, self.ae_final_norm_dense_bias,
                                       self.AE_NORM_DRAM, self.AE_GATE_BCAST_DRAM, apply_gate=False,
                                       gpr_M_reg=ae_S_reg)
                self._debug_op(f"step{step}_final_ada_rms_norm", self.AE_NORM_DRAM, S * H, shape=(S, H))

                # action_out_proj: (S,H) -> v_t (S,64). Output N padded 32->64 (weight
                # rows [32:64]=0) so v_t is physically 64-wide, matching x_t -> the
                # euler update is a plain contiguous add (no strided 32-of-64 write).
                self._ae_matmul(S, H, self.AE_XT_WIDTH, self.AE_NORM_DRAM,
                                 self.ae_action_out_scale, self.ae_action_out_data,
                                 self.AE_VT_DRAM, bias_addr=self.ae_action_out_bias, gpr_M_reg=ae_S_reg)
                self._debug_op(f"step{step}_action_out_proj", self.AE_VT_DRAM, S * self.AE_XT_WIDTH,
                                shape=(S, self.AE_XT_WIDTH))
                if self.DENOISE_STEP0_PROBE and step == 0:
                    self._dram_copy(S * self.AE_XT_WIDTH * 2, self.AE_VT_DRAM, self.AE_P0_VT)

                # Euler step: x_t = x_t + dt * v_t  (both physically S*64-wide)
                # NOTE: OUTPUT_DRAM_ADDR aliases A_DRAM_ADDR (both AE_XT_DRAM) here --
                # same aliasing shape as the compile_prefix bug we fixed, but this
                # buffer is tiny (S*64 elements, a single chunk) so it's mathematically
                # safe by the same per-chunk read-before-write analysis. Left as-is
                # (not the confirmed bug class) but flagging since we've been burned
                # by this exact pattern before.
                self.accelerator_memory_to_sram(self.AE_VT_DRAM, 0x00000, S * self.AE_XT_WIDTH)
                self.broadcast_mul(scalar=dt, sram_start_addr=0x00000, sram_wb_addr=0x00000,
                                    element_size=S * self.AE_XT_WIDTH)
                self.sram_to_accelerator_memory(0x00000, self.AE_VT_DRAM, S * self.AE_XT_WIDTH)
                eltwise_add_core_dram(self, size=S * self.AE_XT_WIDTH, A_DRAM_ADDR=self.AE_XT_DRAM,
                                       B_DRAM_ADDR=self.AE_VT_DRAM, OUTPUT_DRAM_ADDR=self.AE_XT_DRAM)
                self._debug_op(f"step{step}_euler_update", self.AE_XT_DRAM, S * self.AE_XT_WIDTH,
                                shape=(S, self.AE_XT_WIDTH))
                self._dram_copy(S * self.AE_XT_WIDTH * 2, self.AE_XT_DRAM, self.AE_STEP_SNAPSHOT_DRAM[step])
                t += dt

            # Main per-(step,layer) program ends here; the shared flash-attention
            # subroutine (jumped to from every per-head call site inside
            # compile_suffix_step, 1440 sites total) is compiled once below.
            self.generate_instruction_halt()
        except _DebugStop:
            pass   # halt already emitted by _debug_op; fall through to the subroutine compile below.

        ae_sub_start, _ae_flops = self.flash_attention_core(
            head_dim=self.HEAD_DIM, seq_len=Tkv,
            Q_DRAM_ADDR=self.AE_FLASH_Q_DRAM, K_DRAM_ADDR=self.AE_FLASH_K_DRAM,
            V_DRAM_ADDR=self.AE_FLASH_V_DRAM, OUTPUT_DRAM_ADDR=self.AE_FLASH_OUT_DRAM,
            SCRATCH_DRAM_ADDR=self.AE_ATTN_SCRATCH_DRAM, ATTN_P_DRAM_ADDR=self.AE_FLASH_ATTN_P_DRAM,
            IDENTITY_DRAM_ADDR=self.identity_addr, BIAS_DRAM_ADDR=self.AE_BIAS_DRAM,
            gpr_bucket_idx=flash_ctx["gpr_bucket"], num_buckets=flash_ctx["num_buckets"],
            gpr_ret_id=flash_ctx["gpr_ret"])
        for _idx in flash_ctx["call_sites"]:
            self._patch_jump_immediate(_idx, ue_35bit_addr_shifter(ae_sub_start))

        # LIFO release, matching alloc order (ae_S_reg, gpr_bucket, gpr_ret).
        self.release_isa_reg()  # flash_ctx["gpr_ret"]
        self.release_isa_reg()  # flash_ctx["gpr_bucket"]
        self.release_isa_reg()  # ae_S_reg
        print("compile_denoise_loop done: 10-step Euler action-expert flow-matching stack compiled "
              "(statically unrolled, 1440 flash-attention jump sites)")

    # =========================================================================
    # End-to-end driver: real sample images -> vision (x3) -> prefix -> denoise
    # loop -> readback. Integration pass reconciling the vision/prefix/action-
    # expert stacks written independently above.
    # =========================================================================
    def _patchify(self, image_hwc):
        """image_hwc: (224,224,3) float32 in [-1,1] -> (256, 588) float32, matching
        pi05_torch_ref.vision_encode's unfold+reshape (patch_size=14, 16x16 patches)."""
        ps, n_side = 14, 16
        x = image_hwc.reshape(n_side, ps, n_side, ps, 3)
        x = x.transpose(0, 2, 1, 3, 4).reshape(n_side * n_side, ps * ps * 3)
        return x

    def run_vision(self, images_hwc):
        """images_hwc: list of 3 (224,224,3) float32 numpy arrays in [-1,1].
        Runs compile_encoder() once per image slot, returns (3*256, 2048) bf16
        tensor of concatenated vision tokens (host-side, read back via DMA)."""
        HO = self.VIS_HEAD_OUT
        S = self.VIS_S
        PK = self.VIS_PATCH_K
        outs = []

        # compile_encoder() is a pure function of the (fixed) weights -- it never
        # touches the slot index or pixel data, only VIS_PIXEL_IN_DRAM's *contents*
        # vary per slot. So the compiled program is identical for all 3 slots;
        # compile once and just re-DMA pixels + re-execute for slots 1/2.
        global _SILENT_MODE
        _original_print("  [vision encoder] compiling...", end="\r", flush=True)
        t_compile0 = time.perf_counter()
        _SILENT_MODE = True
        try:
            prog_addr = self.compile_encoder()
        finally:
            _SILENT_MODE = False
        _original_print(f"  [vision encoder] compiled in {time.perf_counter()-t_compile0:.1f}s" + " " * 20)

        for i, img in enumerate(images_hwc):
            patches = self._patchify(img)  # (256, 588)
            patches_pad = np.zeros((S, PK), dtype=np.float32)
            patches_pad[:, :patches.shape[1]] = patches
            pixel_t = torch.from_numpy(patches_pad).to(torch.bfloat16)
            self.dma_write(DMA_DEVICE_H2C, self.VIS_PIXEL_IN_DRAM, pixel_t, S * PK * 2)

            self.start_execute_from_dram(prog_addr)
            self._wait_with_heartbeat(f"vision slot {i}", timeout=180.0)

            buf = bytearray(S * HO * 2)
            self.dma_read(DMA_DEVICE_C2H, self.VIS_HEAD_OUT_DRAM, buf, len(buf))
            out = torch.frombuffer(bytes(buf), dtype=torch.bfloat16).reshape(S, HO).clone()
            outs.append(out)
            print(f"  [vision] slot {i} done")
        return torch.cat(outs, dim=0)  # (3*256, 2048)

    def _vision_snr_check(self, images_hwc, hw_vision_tokens):
        """CPU-vs-HW SNR check for the vision encoder output, using the SAME
        IF4-quantized weights (pi05_torch_ref.py's Weights(quant='if4')) so
        this isolates HW execution/precision drift, not a quantization-policy
        mismatch. images_hwc: the same list of 3 (224,224,3) float32 arrays
        [-1,1] passed to run_vision(). hw_vision_tokens: (768, 2048) bf16,
        run_vision()'s return value. Prints per-slot and overall SNR in dB
        (>=40dB is this codebase's usual correctness bar, see
        feedback_mobilesam_snr_validation_contract)."""
        import pi05_torch_ref as _ref
        W = _ref.Weights(device="cpu", dtype=torch.bfloat16, quant="if4")
        images_t = torch.stack([torch.from_numpy(im) for im in images_hwc], dim=0).to(torch.bfloat16)
        cpu_tokens = _ref.vision_encode(images_t, W).reshape(-1, hw_vision_tokens.shape[-1])  # (768, 2048)

        hw = hw_vision_tokens.float()
        cpu = cpu_tokens.float()
        print("=== vision encoder CPU-vs-HW SNR check ===")
        S = self.VIS_S
        for i, name in enumerate(("main", "wrist", "pad")):
            h, c = hw[i * S:(i + 1) * S], cpu[i * S:(i + 1) * S]
            noise = (h - c).pow(2).sum().sqrt()
            signal = c.pow(2).sum().sqrt()
            snr_db = 20 * torch.log10(signal / noise.clamp_min(1e-12))
            print(f"  slot {i} ({name}): SNR={snr_db:.2f}dB  hw[min={h.min():.3f},max={h.max():.3f}] "
                  f"cpu[min={c.min():.3f},max={c.max():.3f}]")
        noise = (hw - cpu).pow(2).sum().sqrt()
        signal = cpu.pow(2).sum().sqrt()
        overall_snr_db = 20 * torch.log10(signal / noise.clamp_min(1e-12))
        print(f"  overall: SNR={overall_snr_db:.2f}dB")

    def _prefix_snr_check(self, prompt_tokens, vision_tokens, valid_len):
        """CPU-vs-HW SNR check for the prefix's K/V cache (layer 0 and the
        last layer), same IF4-quantized weights as _vision_snr_check. Runs
        the CPU reference's prefix_forward on the UNPADDED (vision + real
        text tokens only, valid_len rows) prefix -- our HW pads to seq_len
        with epsilon-fill rows the CPU reference has no equivalent of, so
        only the first valid_len rows of the HW K/V cache are comparable."""
        import pi05_torch_ref as _ref
        W = _ref.Weights(device="cpu", dtype=torch.bfloat16, quant="if4")

        embed_table = W["PaliGemma.llm.embedder.input_embedding"]
        tid = torch.tensor(prompt_tokens, dtype=torch.long)
        text_tokens = embed_table[tid].to(torch.bfloat16)  # (n_text, 2048)
        n_vis = vision_tokens.shape[0]
        prefix_tokens = torch.cat([vision_tokens.to(torch.bfloat16), text_tokens], dim=0)[None]  # (1, valid_len, 2048)
        assert prefix_tokens.shape[1] == valid_len

        prefix_bias = _ref.build_prefix_attn_bias(valid_len, "cpu", torch.float32)
        _, (k_cache, v_cache) = _ref.prefix_forward(prefix_tokens, prefix_bias, W)

        P, D = self.PREFIX_SEQ_LEN, self.HEAD_DIM
        print("=== prefix K/V CPU-vs-HW SNR check ===")
        for layer in (0, self.NUM_LAYERS - 1):
            for name, hw_addr, cpu_t in (
                ("K", self.prefix_k_cache_addr[layer], k_cache[layer]),
                ("V", self.prefix_v_cache_addr[layer], v_cache[layer]),
            ):
                buf = bytearray(P * D * 2)
                self.dma_read(DMA_DEVICE_C2H, hw_addr, buf, len(buf))
                hw = torch.frombuffer(bytes(buf), dtype=torch.bfloat16).reshape(P, D).float()[:valid_len]
                cpu = cpu_t.reshape(-1, D).float()[:valid_len]
                noise = (hw - cpu).pow(2).sum().sqrt()
                signal = cpu.pow(2).sum().sqrt()
                snr_db = 20 * torch.log10(signal / noise.clamp_min(1e-12))
                print(f"  layer{layer} {name}: SNR={snr_db:.2f}dB  hw[min={hw.min():.3f},max={hw.max():.3f}] "
                      f"cpu[min={cpu.min():.3f},max={cpu.max():.3f}]")

    def _prefix_layer_snr_report(self, prompt_tokens, vision_tokens, valid_len):
        """Per-layer CPU-vs-HW SNR for the prefix's hidden-state output (post
        residual2, every layer), using PREFIX_LAYER_SNAPSHOT_DRAM. Answers
        'is the divergence already there in layer0, or does it accumulate?' --
        reimplements pi05_torch_ref.prefix_forward's loop body layer-by-layer
        (instead of calling it directly) so we can grab x after each layer,
        not just the final K/V cache."""
        import pi05_torch_ref as _ref
        W = _ref.Weights(device="cpu", dtype=torch.bfloat16, quant="if4")

        embed_table = W["PaliGemma.llm.embedder.input_embedding"]
        tid = torch.tensor(prompt_tokens, dtype=torch.long)
        text_tokens = embed_table[tid].to(torch.bfloat16)
        prefix_tokens = torch.cat([vision_tokens.to(torch.bfloat16), text_tokens], dim=0)[None]
        assert prefix_tokens.shape[1] == valid_len
        prefix_bias = _ref.build_prefix_attn_bias(valid_len, "cpu", torch.float32)

        x = prefix_tokens
        print("=== prefix per-layer hidden-state CPU-vs-HW SNR report ===")
        for layer in range(self.NUM_LAYERS):
            norm_s = W["PaliGemma.llm.layers.pre_attention_norm.scale"][layer]
            h = _ref.rms_norm(x, norm_s)
            attn_out, _, _ = _ref.joint_attention(h, None, prefix_bias, layer, W)
            x = x + attn_out

            norm2_s = W["PaliGemma.llm.layers.pre_ffw_norm.scale"][layer]
            h2 = _ref.rms_norm(x, norm2_s)
            mlp_out = _ref.gated_mlp(h2, W["PaliGemma.llm.layers.mlp.gating_einsum"][layer],
                                      W["PaliGemma.llm.layers.mlp.linear"][layer])
            x = x + mlp_out
            cpu_layer = x[0].float()  # (valid_len, H)

            addr = self.PREFIX_LAYER_SNAPSHOT_DRAM[layer]
            S, H = self.PREFIX_SEQ_LEN, self.HIDDEN_SIZE
            buf = bytearray(S * H * 2)
            self.dma_read(DMA_DEVICE_C2H, addr, buf, len(buf))
            hw_layer = torch.frombuffer(bytes(buf), dtype=torch.bfloat16).reshape(S, H).float()[:valid_len]

            noise = (hw_layer - cpu_layer).pow(2).sum().sqrt()
            signal = cpu_layer.pow(2).sum().sqrt()
            snr_db = 20 * torch.log10(signal / noise.clamp_min(1e-12))
            print(f"  layer{layer}: SNR={snr_db:.2f}dB  hw[min={hw_layer.min():.3f},max={hw_layer.max():.3f}] "
                  f"cpu[min={cpu_layer.min():.3f},max={cpu_layer.max():.3f}]")

    def _prefix_layer0_op_snr_report(self, prompt_tokens, vision_tokens, valid_len):
        """Op-by-op CPU-vs-HW SNR for layer0 ONLY, using PREFIX_L0_SNAPSHOT_DRAM
        (layer0's scratch buffers snapshotted before layer1 overwrites them).
        Reimplements joint_attention's internals manually (instead of calling
        it as a black box) so every HW checkpoint (ln1, q/k/v proj, q_permute,
        head0-7, attn_permute, o_proj_residual, ln2, mlp_lo/hi/down) has a
        directly matching CPU intermediate to diff against -- pinpoints
        exactly which op inside layer0 first diverges."""
        import pi05_torch_ref as _ref
        import torch.nn.functional as _F
        W = _ref.Weights(device="cpu", dtype=torch.bfloat16, quant="if4")

        embed_table = W["PaliGemma.llm.embedder.input_embedding"]
        tid = torch.tensor(prompt_tokens, dtype=torch.long)
        text_tokens = embed_table[tid].to(torch.bfloat16)
        x_in = torch.cat([vision_tokens.to(torch.bfloat16), text_tokens], dim=0)[None]  # (1, valid_len, H)
        assert x_in.shape[1] == valid_len

        S, H, D = self.PREFIX_SEQ_LEN, self.HIDDEN_SIZE, self.HEAD_DIM
        NH = self.NUM_HEADS
        snap = self.PREFIX_L0_SNAPSHOT_DRAM

        def _hw(name, numel, shape):
            buf = bytearray(numel * 2)
            self.dma_read(DMA_DEVICE_C2H, snap[name], buf, len(buf))
            return torch.frombuffer(bytes(buf), dtype=torch.bfloat16).reshape(shape).clone().float()

        def _snr(hw_t, cpu_t):
            hw_t, cpu_t = hw_t.float(), cpu_t.float()
            noise = (hw_t - cpu_t).pow(2).sum().sqrt()
            signal = cpu_t.pow(2).sum().sqrt()
            return (20 * torch.log10(signal / noise.clamp_min(1e-12))).item(), hw_t, cpu_t

        def _report(name, hw_t, cpu_t):
            snr_db, hw_t, cpu_t = _snr(hw_t, cpu_t)
            print(f"  {name}: SNR={snr_db:.2f}dB  hw[min={hw_t.min():.3f},max={hw_t.max():.3f}] "
                  f"cpu[min={cpu_t.min():.3f},max={cpu_t.max():.3f}]")

        print("=== prefix layer0 op-by-op CPU-vs-HW SNR report ===")

        # 1. ln1
        norm_s = W["PaliGemma.llm.layers.pre_attention_norm.scale"][0]
        h = _ref.rms_norm(x_in, norm_s)
        _report("ln1", _hw("ln1", S * H, (S, H))[:valid_len], h[0])

        # 2. q/k/v proj
        q_ein = W["PaliGemma.llm.layers.attn.q_einsum.w"][0]     # (8, 2048, 256)
        kv_ein = W["PaliGemma.llm.layers.attn.kv_einsum.w"][0]   # (2, 1, 2048, 256)
        q_pre = torch.einsum("btd,hdk->bthk", h, q_ein)          # (1, T, 8, 256)
        k_pre = torch.einsum("btd,hdc->bthc", h, kv_ein[0])      # (1, T, 1, 256)
        v_pre = torch.einsum("btd,hdc->bthc", h, kv_ein[1])
        _report("q_proj", _hw("q_proj", S * H, (S, H))[:valid_len], q_pre[0].reshape(-1, NH * D))
        _report("k_proj", _hw("k_proj", S * D, (S, D))[:valid_len], k_pre[0].reshape(-1, D))
        _report("v_proj", _hw("v_proj", S * D, (S, D))[:valid_len], v_pre[0].reshape(-1, D))

        # 3. q_permute: (seq,heads,D) -> (heads,seq,D); HW buffer's TRUE layout is
        # (NH, S, D) flattened, NOT a plain (S,H) reshape despite the debug_op shape arg.
        q_perm_cpu = q_pre[0].permute(1, 0, 2)  # (8, T, 256)
        q_perm_hw = _hw("q_permute", S * H, (NH, S, D))[:, :valid_len, :]
        _report("q_permute", q_perm_hw, q_perm_cpu)

        # 4. per-head attention (bidirectional, no mask -- prefix_bias is all-zero)
        qf = q_pre.permute(0, 2, 1, 3).float()                      # (1, 8, T, 256)
        kf = k_pre.permute(0, 2, 1, 3).float().expand(-1, NH, -1, -1)
        vf = v_pre.permute(0, 2, 1, 3).float().expand(-1, NH, -1, -1)
        attn = _F.scaled_dot_product_attention(qf, kf, vf)         # (1, 8, T, 256)
        for hd in range(NH):
            hw_head = _hw(f"head{hd}", S * D, (S, D))[:valid_len]
            _report(f"head{hd}", hw_head, attn[0, hd])

        # 5. attn_permute: (heads,seq,D) -> (seq, heads*D), token-major again
        attn_permuted_cpu = attn[0].permute(1, 0, 2).reshape(-1, NH * D)  # (T, 2048)
        _report("attn_permute", _hw("attn_permute", S * H, (S, H))[:valid_len], attn_permuted_cpu)

        # 6. o_proj + residual
        o_ein = W["PaliGemma.llm.layers.attn.attn_vec_einsum.w"][0]  # (8, 256, 2048)
        pre_attn_out = torch.einsum("thk,hkd->td", attn[0].permute(1, 0, 2).to(x_in.dtype), o_ein)
        o_proj_residual_cpu = x_in[0] + pre_attn_out
        _report("o_proj_residual", _hw("o_proj_residual", S * H, (S, H))[:valid_len], o_proj_residual_cpu)

        # 7. ln2
        norm2_s = W["PaliGemma.llm.layers.pre_ffw_norm.scale"][0]
        h2 = _ref.rms_norm(o_proj_residual_cpu[None], norm2_s)
        _report("ln2", _hw("ln2", S * H, (S, H))[:valid_len], h2[0])

        # 8. gated-GELU MLP, FF_HALF split (matches HW's parakeet-style N-split)
        gating = W["PaliGemma.llm.layers.mlp.gating_einsum"][0]  # (2, H, I)
        linear = W["PaliGemma.llm.layers.mlp.linear"][0]         # (I, H)
        I = gating.shape[-1]
        FF_HALF = I // 2
        gate_w, up_w = gating[0], gating[1]
        mlp_halves = {}
        for name, sl in (("mlp_lo", slice(0, FF_HALF)), ("mlp_hi", slice(FF_HALF, I))):
            gate_act = _F.gelu(h2 @ gate_w[:, sl], approximate="none")
            up = h2 @ up_w[:, sl]
            mlp_half = (gate_act * up) @ linear[sl, :]
            mlp_halves[name] = mlp_half
            _report(name, _hw(name, S * H, (S, H))[:valid_len], mlp_half[0])

        mlp_down_cpu = (mlp_halves["mlp_lo"] + mlp_halves["mlp_hi"])[0]
        _report("mlp_down", _hw("mlp_down", S * H, (S, H))[:valid_len], mlp_down_cpu)

    def probe_nan_report(self):
        """Post-run bulk NaN/Inf scan of every vision layer + every denoise step,
        using the snapshot buffers compile_encoder/compile_denoise_loop copy
        each layer/step's output into during the single real run (see
        VIS_LAYER_SNAPSHOT_DRAM / AE_STEP_SNAPSHOT_DRAM). Cheap: one DMA read
        per layer/step, no recompiling or re-executing anything -- call this
        once after run_inference() (or run_vision()/compile_denoise_loop()
        individually) to see exactly where (if anywhere) NaN first appears,
        instead of guessing or paying for N separate halt-recompile-rerun probes."""
        S_vis, H_vis = self.VIS_S, self.VIS_H
        print("=== vision layer NaN report ===")
        first_bad = None
        for i, addr in enumerate(getattr(self, "VIS_LAYER_SNAPSHOT_DRAM", [])):
            buf = bytearray(S_vis * H_vis * 2)
            self.dma_read(DMA_DEVICE_C2H, addr, buf, len(buf))
            out = torch.frombuffer(bytes(buf), dtype=torch.bfloat16).reshape(S_vis, H_vis).float()
            n_nan, n_inf = torch.isnan(out).sum().item(), torch.isinf(out).sum().item()
            flag = " <-- FIRST BAD" if (n_nan or n_inf) and first_bad is None else ""
            if flag:
                first_bad = f"vision_layer{i}"
            print(f"  vision_layer{i}: nan={n_nan} inf={n_inf} min={out.min():.4f} max={out.max():.4f}{flag}")

        print("=== denoise step NaN report ===")
        S_ae, AD = self.AE_ACTION_HORIZON_PADDED, self.AE_XT_WIDTH  # snapshots are 64-wide
        for i, addr in enumerate(getattr(self, "AE_STEP_SNAPSHOT_DRAM", [])):
            buf = bytearray(S_ae * AD * 2)
            self.dma_read(DMA_DEVICE_C2H, addr, buf, len(buf))
            out = torch.frombuffer(bytes(buf), dtype=torch.bfloat16).reshape(S_ae, AD).float()
            n_nan, n_inf = torch.isnan(out).sum().item(), torch.isinf(out).sum().item()
            flag = " <-- FIRST BAD" if (n_nan or n_inf) and first_bad is None else ""
            if flag:
                first_bad = f"denoise_step{i}"
            print(f"  denoise_step{i}: nan={n_nan} inf={n_inf} min={out.min():.4f} max={out.max():.4f}{flag}")

        print(f"first bad checkpoint: {first_bad or 'none -- all clean'}")
        return first_bad

    def dump_prefix_kv(self, path):
        """Dump the persistent prefix K/V cache (LAYER0_K_DRAM/LAYER0_V_DRAM,
        all NUM_LAYERS layers) + PREFIX_SEQ_LEN/prefix_valid_len to a single
        .npz on disk, so a later --debug run can reload it and skip the ~185s
        vision+prefix recompute entirely when only iterating on the denoise
        loop. Call after compile_prefix has run (self.prefix_valid_len set)."""
        kv_total = self.NUM_LAYERS * self.KV_LAYER_STRIDE
        buf_k = bytearray(kv_total)
        buf_v = bytearray(kv_total)
        self.dma_read(DMA_DEVICE_C2H, self.LAYER0_K_DRAM, buf_k, kv_total)
        self.dma_read(DMA_DEVICE_C2H, self.LAYER0_V_DRAM, buf_v, kv_total)
        np.savez(path, k=np.frombuffer(bytes(buf_k), dtype=np.uint16),
                  v=np.frombuffer(bytes(buf_v), dtype=np.uint16),
                  prefix_seq_len=self.PREFIX_SEQ_LEN, prefix_valid_len=self.prefix_valid_len)
        print(f"[dump_prefix_kv] wrote {path} ({kv_total*2/1024/1024:.1f} MB K + V, "
              f"seq_len={self.PREFIX_SEQ_LEN}, valid_len={self.prefix_valid_len})")
        # Keep an in-memory copy of exactly what was just read, so a later
        # verify_prefix_kv() call in the SAME run/process can diff against it
        # without a disk round-trip (rules out any save/load bug too).
        self._prefix_kv_snapshot = (bytes(buf_k), bytes(buf_v))

    def verify_prefix_kv(self, label=""):
        """Re-read LAYER0_K_DRAM/LAYER0_V_DRAM right now and diff against the
        snapshot dump_prefix_kv took earlier in this SAME run/process. Tests
        whether anything between compile_prefix finishing and this call
        clobbers the prefix K/V cache in place -- if this reports a mismatch,
        the corruption happens between prefix and here (e.g. a DRAM-address
        collision from a later allocation); if it reports clean, the K/V cache
        itself is still intact at this point and the corruption (if any) must
        happen later, inside compile_denoise_loop's own execution."""
        assert hasattr(self, "_prefix_kv_snapshot"), \
            "verify_prefix_kv() called with no prior dump_prefix_kv() snapshot in this run"
        kv_total = self.NUM_LAYERS * self.KV_LAYER_STRIDE
        buf_k = bytearray(kv_total)
        buf_v = bytearray(kv_total)
        self.dma_read(DMA_DEVICE_C2H, self.LAYER0_K_DRAM, buf_k, kv_total)
        self.dma_read(DMA_DEVICE_C2H, self.LAYER0_V_DRAM, buf_v, kv_total)
        snap_k, snap_v = self._prefix_kv_snapshot
        now_k, now_v = bytes(buf_k), bytes(buf_v)
        k_match = now_k == snap_k
        v_match = now_v == snap_v
        if k_match and v_match:
            print(f"[verify_prefix_kv{f' {label}' if label else ''}] MATCH -- prefix K/V cache "
                  f"is byte-identical to the post-compile_prefix snapshot")
        else:
            k_arr = torch.frombuffer(now_k, dtype=torch.bfloat16).float()
            snap_k_arr = torch.frombuffer(snap_k, dtype=torch.bfloat16).float()
            v_arr = torch.frombuffer(now_v, dtype=torch.bfloat16).float()
            snap_v_arr = torch.frombuffer(snap_v, dtype=torch.bfloat16).float()
            k_diff = (k_arr - snap_k_arr).abs()
            v_diff = (v_arr - snap_v_arr).abs()
            print(f"[verify_prefix_kv{f' {label}' if label else ''}] MISMATCH -- prefix K/V cache "
                  f"changed since compile_prefix finished! "
                  f"K: match={k_match} max_abs_diff={k_diff.max().item():.4f} "
                  f"n_diff={int((k_diff > 0).sum().item())}/{k_diff.numel()} "
                  f"V: match={v_match} max_abs_diff={v_diff.max().item():.4f} "
                  f"n_diff={int((v_diff > 0).sum().item())}/{v_diff.numel()}")

    def verify_denoise_step0(self, kv_npz_path, device="cuda"):
        """Diff the FPGA's step-0 action-expert intermediates against a torch
        reference computed with the SAME noise and the SAME prefix K/V (loaded
        from kv_npz_path). Feeding the reference the FPGA's own K/V isolates the
        action-expert forward -- any divergence here is a kernel bug, not a
        prefix problem. Prints SNR per intermediate so the FIRST one that craters
        pinpoints the broken op. Requires DENOISE_STEP0_PROBE=True during compile."""
        import pi05_torch_ref as _ref
        import torch.nn.functional as F
        if not torch.cuda.is_available():
            device = "cpu"
        S, H, D = self.AE_ACTION_HORIZON_PADDED, self.AE_HIDDEN, self.HEAD_DIM
        AH, AD = self.AE_ACTION_HORIZON, self.AE_ACTION_DIM_PADDED

        def _read(addr, numel):
            buf = bytearray(numel * 2)
            self.dma_read(DMA_DEVICE_C2H, addr, buf, numel * 2)
            return torch.frombuffer(bytes(buf), dtype=torch.bfloat16).float()

        fpga_in   = _read(self.AE_P0_ACTION_IN, S * H).reshape(S, H)[:AH]
        fpga_time = _read(self.AE_P0_TIME_EMB, H).reshape(1, H)
        fpga_l0   = _read(self.AE_P0_SUF_L0, S * H).reshape(S, H)[:AH]
        fpga_l17  = _read(self.AE_P0_SUF_L17, S * H).reshape(S, H)[:AH]
        XW = self.AE_XT_WIDTH
        fpga_vt   = _read(self.AE_P0_VT, S * XW).reshape(S, XW)[:AH, :7]
        fpga_xtpad = _read(self.AE_P0_XT_PAD, S * XW).reshape(S, XW)[:AH]  # 64-wide input to action_in_proj
        fpga_l0norm  = _read(self.AE_P0_L0_NORM, S * H).reshape(S, H)[:AH]
        fpga_l0attn  = _read(self.AE_P0_L0_ATTN, S * H).reshape(S, H)[:AH]
        fpga_l0resid = _read(self.AE_P0_L0_RESID, S * H).reshape(S, H)[:AH]

        # --- reference step-0 with FPGA's own K/V ---
        npz = np.load(kv_npz_path)
        vlen = int(npz["prefix_valid_len"])
        stride = npz["k"].size // (self.NUM_LAYERS * D)
        fk = torch.frombuffer(npz["k"].tobytes(), dtype=torch.bfloat16).float().reshape(self.NUM_LAYERS, stride, D)
        fv = torch.frombuffer(npz["v"].tobytes(), dtype=torch.bfloat16).float().reshape(self.NUM_LAYERS, stride, D)
        W = _ref.Weights(device=device, dtype=torch.bfloat16, quant="if4")
        dt_ = W.dtype
        # (b,P,1,D) kv cache from the FPGA's cached prefix rows [0:vlen]
        k_cache = [fk[L, :vlen].to(device, dt_)[None, :, None, :] for L in range(self.NUM_LAYERS)]
        v_cache = [fv[L, :vlen].to(device, dt_)[None, :, None, :] for L in range(self.NUM_LAYERS)]
        kv_cache = (k_cache, v_cache)

        noise = torch.zeros(1, AH, AD, device=device, dtype=torch.float32)
        noise[..., :7] = torch.from_numpy(np.random.RandomState(0).randn(AH, 7).astype(np.float32)).to(device)
        x_t = noise
        t = torch.ones(1, device=device, dtype=torch.float32)

        ref_in = (x_t.to(dt_) @ W["action_in_proj.kernel"]) + W["action_in_proj.bias"]  # (1,AH,H)
        time_emb = _ref.sincos_pos_embed(t, dim=H).to(dt_)
        time_emb = F.silu((time_emb @ W["time_mlp_in.kernel"]) + W["time_mlp_in.bias"])
        time_emb = F.silu((time_emb @ W["time_mlp_out.kernel"]) + W["time_mlp_out.bias"])  # (1,H)

        suffix_bias = _ref.build_suffix_attn_bias(vlen, AH, device, torch.float32)
        x = ref_in
        ref_layer_out = {}
        for layer in range(self.NUM_LAYERS):
            dw = W["PaliGemma.llm.layers.pre_attention_norm_1.Dense_0.kernel"][layer]
            db = W["PaliGemma.llm.layers.pre_attention_norm_1.Dense_0.bias"][layer]
            h, gate = _ref.ada_rms_norm(x, time_emb, dw, db)
            _, attn_out, _ = _ref.joint_attention(None, h, suffix_bias, layer, W, kv_cache=kv_cache)
            if layer == 0:
                ref_l0norm, ref_l0attn = h, attn_out
            x = x + gate[:, None, :] * attn_out
            if layer == 0:
                ref_l0resid = x
            dw2 = W["PaliGemma.llm.layers.pre_ffw_norm_1.Dense_0.kernel"][layer]
            db2 = W["PaliGemma.llm.layers.pre_ffw_norm_1.Dense_0.bias"][layer]
            h2, gate2 = _ref.ada_rms_norm(x, time_emb, dw2, db2)
            mlp_out = _ref.gated_mlp(h2, W["PaliGemma.llm.layers.mlp_1.gating_einsum"][layer],
                                     W["PaliGemma.llm.layers.mlp_1.linear"][layer])
            x = x + gate2[:, None, :] * mlp_out
            ref_layer_out[layer] = x
        fdw = W["PaliGemma.llm.final_norm_1.Dense_0.kernel"]
        fdb = W["PaliGemma.llm.final_norm_1.Dense_0.bias"]
        x_norm, _ = _ref.ada_rms_norm(x, time_emb, fdw, fdb)
        ref_vt = ((x_norm.float() @ W["action_out_proj.kernel"].float()) + W["action_out_proj.bias"].float())[..., :7]

        def _snr(a, b):
            a, b = a.float().cpu(), b.float().cpu()
            return 20 * torch.log10(b.norm() / (a - b).norm().clamp_min(1e-12)).item()

        # staged x_t_pad check: expected (AH,64) = [noise(AH,32) | zeros(AH,32)]
        exp_xtpad = torch.zeros(AH, 64)
        exp_xtpad[:, :AD] = noise.squeeze(0).float().cpu()
        print("=== Step-0 action-expert intermediate SNR: FPGA vs reference (same noise + FPGA K/V) ===")
        print(f"  x_t_pad (staged input) : {_snr(fpga_xtpad, exp_xtpad):7.2f}dB   "
              f"[cols0:7 {'OK' if torch.allclose(fpga_xtpad[:, :7], exp_xtpad[:, :7], atol=0.05) else 'MISMATCH'}, "
              f"cols32:64 max={fpga_xtpad[:, 32:].abs().max().item():.3f} (expect ~0)]")
        torch.set_printoptions(precision=4, sci_mode=False)
        print(f"    [raw] FPGA x_t_pad rows0-2, cols0:8:\n{fpga_xtpad[:3, :8]}")
        print(f"    [raw] EXPECTED       rows0-2, cols0:8:\n{exp_xtpad[:3, :8]}")
        print(f"    [raw] FPGA x_t_pad col0 (all 10 rows): {fpga_xtpad[:, 0].tolist()}")
        print(f"    [raw] EXPECTED       col0 (all 10 rows): {exp_xtpad[:, 0].tolist()}")
        print(f"  action_in_proj : {_snr(fpga_in,   ref_in.squeeze(0)):7.2f}dB")
        print(f"  time_embed     : {_snr(fpga_time, time_emb):7.2f}dB")
        print(f"  -- layer0 internals --")
        print(f"    L0 preattn_norm : {_snr(fpga_l0norm,  ref_l0norm.squeeze(0)):7.2f}dB")
        print(f"    L0 attn_out     : {_snr(fpga_l0attn,  ref_l0attn.squeeze(0)):7.2f}dB")
        print(f"    L0 attn_residual: {_snr(fpga_l0resid, ref_l0resid.squeeze(0)):7.2f}dB")
        print(f"  suffix_layer0  : {_snr(fpga_l0,   ref_layer_out[0].squeeze(0)):7.2f}dB")
        print(f"  suffix_layer17 : {_snr(fpga_l17,  ref_layer_out[self.NUM_LAYERS-1].squeeze(0)):7.2f}dB")
        print(f"  v_t (out_proj) : {_snr(fpga_vt,   ref_vt.squeeze(0)):7.2f}dB")
        print("  ^ first line that craters (<~10dB) = the op that breaks. All high = bug is downstream (euler/snapshot).")

    def _run_sanity_matmul(self, M, K, N, use_pbi):
        """Compile+run ONE plain bf16 A(M,K) @ B(K,N) matmul (A @ B^T) and
        return (hw_out, cpu_out). If use_pbi, drive the M-loop through a
        freshly-allocated gpr primed with ADD_SET(M) -- byte-for-byte the same
        register-priming path compile_denoise_loop uses for ae_S_reg (which,
        in a full run, reuses the exact physical GPR index prefix left dirty).
        If not use_pbi, use the legacy static-M path (what the first passing
        sanity check exercised)."""
        torch.manual_seed(0)
        A = torch.randn(M, K, dtype=torch.bfloat16)
        B = torch.randn(N, K, dtype=torch.bfloat16)  # (N,K), matmat_mul_core computes A @ B^T
        bpe = 2
        a_addr = store_weight(self, A)
        b_addr = store_weight(self, B)
        out_addr = self.allocate_tensor_dram(M * N * bpe)

        self.start_capture()
        gpr_M_reg = None
        if use_pbi:
            gpr_M_reg = self.alloc_isa_reg()
            self.generate_instruction_add_set(gpr_M_reg, M)
        self.matmat_mul_core(M=M, K=K, N=N, A_DRAM_ADDR=a_addr, B_DRAM_ADDR=b_addr,
                              OUTPUT_DRAM_ADDR=out_addr, gpr_M_reg=gpr_M_reg)
        self.generate_instruction_halt()
        all_bytes = bytearray()
        for inst in self.capture_buffer:
            all_bytes.extend(inst.get_bytes())
        prog_addr = self.get_program_dram_addr()
        self._dma_write_retry(DMA_DEVICE_H2C, prog_addr, all_bytes, len(all_bytes))
        self.allocate_program_dram(len(all_bytes))
        self.clear_capture_buffer()
        self.stop_capture()
        if use_pbi:
            self.release_isa_reg()

        self.start_execute_from_dram(prog_addr)
        self._wait_with_heartbeat(f"sanity_matmul_{'pbi' if use_pbi else 'legacy'}", timeout=30.0)

        buf = bytearray(M * N * bpe)
        self.dma_read(DMA_DEVICE_C2H, out_addr, buf, len(buf))
        hw_out = torch.frombuffer(bytes(buf), dtype=torch.bfloat16).reshape(M, N).clone().float()
        cpu_out = (A.float() @ B.float().T)
        return hw_out, cpu_out

    def sanity_matmul_check(self, M=64, K=64, N=64):
        """Post-vision+prefix hardware-health check. Runs the SAME plain bf16
        matmul twice: once via the legacy static-M path (which the first
        passing sanity check used), once via the PBI runtime-M path (gpr_M_reg
        primed with ADD_SET -- exactly what compile_denoise_loop's every op
        uses, and which reuses the physical GPR index prefix left dirty). If
        legacy PASSes but PBI FAILs, the bug is isolated to register/PBI state
        carried over from prefix's execution, NOT the compute datapath and NOT
        anything denoise-specific."""
        results = {}
        for use_pbi in (False, True):
            hw_out, cpu_out = self._run_sanity_matmul(M, K, N, use_pbi)
            n_nan = torch.isnan(hw_out).sum().item()
            n_inf = torch.isinf(hw_out).sum().item()
            snr_db = 20 * torch.log10(cpu_out.norm() / (hw_out - cpu_out).norm().clamp_min(1e-12)).item()
            passed = n_nan == 0 and n_inf == 0 and snr_db >= 30.0
            tag = "PBI (gpr_M_reg, like denoise)" if use_pbi else "legacy (static-M, like 1st sanity)"
            print(f"[sanity_matmul_check] {tag} M={M} K={K} N={N}: nan={n_nan} inf={n_inf} "
                  f"SNR={snr_db:.2f}dB hw[min={hw_out.min():.4f},max={hw_out.max():.4f}] "
                  f"-- {'PASS' if passed else 'FAIL'}")
            results[use_pbi] = passed
        if results[False] and not results[True]:
            print("[sanity_matmul_check] >>> LEGACY PASS + PBI FAIL: the NaN is a PBI/register "
                  "state carryover from prefix, NOT the compute datapath. Prime/reset gpr_M_reg "
                  "state before denoise. <<<")
        return results

    def load_prefix_kv(self, path):
        """Inverse of dump_prefix_kv: DMA the saved K/V bytes back into
        LAYER0_K_DRAM/LAYER0_V_DRAM (already allocated by tensor_init) and
        restore PREFIX_SEQ_LEN/prefix_valid_len/prefix_k_cache_addr/
        prefix_v_cache_addr -- the exact state compile_prefix normally leaves
        behind -- so tensor_init_action_expert/compile_denoise_loop can run
        with no vision/prefix stage at all."""
        npz = np.load(path)
        kv_total = self.NUM_LAYERS * self.KV_LAYER_STRIDE
        assert npz["k"].nbytes == kv_total, \
            f"dumped K size {npz['k'].nbytes} != current KV_LAYER_STRIDE*NUM_LAYERS {kv_total} (shape mismatch)"
        self._dma_write_retry(DMA_DEVICE_H2C, self.LAYER0_K_DRAM, npz["k"].tobytes(), kv_total)
        self._dma_write_retry(DMA_DEVICE_H2C, self.LAYER0_V_DRAM, npz["v"].tobytes(), kv_total)
        self.PREFIX_SEQ_LEN = int(npz["prefix_seq_len"])
        self.prefix_valid_len = int(npz["prefix_valid_len"])
        self.prefix_k_cache_addr = [self.LAYER0_K_DRAM + l * self.KV_LAYER_STRIDE for l in range(self.NUM_LAYERS)]
        self.prefix_v_cache_addr = [self.LAYER0_V_DRAM + l * self.KV_LAYER_STRIDE for l in range(self.NUM_LAYERS)]
        print(f"[load_prefix_kv] loaded {path}: seq_len={self.PREFIX_SEQ_LEN}, valid_len={self.prefix_valid_len}")

    def run_inference(self, images_hwc, prompt_tokens, noise32=None, skip_prefix=False, dump_prefix_path=None,
                       verify_prefix_kv=False, sanity_check=False):
        """Full forward pass on real hardware. images_hwc: list of 3 (224,224,3)
        float32 arrays in [-1,1]. prompt_tokens: 1-D list/array of token ids.
        Returns (10,32) numpy action array (caller slices [:, :7]).

        skip_prefix: if True, skip run_vision()/compile_prefix() entirely and
        assume load_prefix_kv() was already called to populate LAYER0_K_DRAM/
        LAYER0_V_DRAM/PREFIX_SEQ_LEN/prefix_valid_len -- for fast denoise-only
        iteration (--debug flag in main()). images_hwc/prompt_tokens are
        ignored in this mode.
        dump_prefix_path: if set (and skip_prefix is False), dump the fresh
        prefix K/V cache to this path right after compile_prefix, for a later
        --debug run to reload.
        sanity_check: (--sanity-check in main()) after vision+prefix run for
        real, run sanity_matmul_check() instead of the action-expert/denoise
        stage and return None -- tests raw hardware health with the simplest
        possible op after vision+prefix's execution, independent of anything
        denoise-loop-specific."""
        t0 = time.perf_counter()
        if skip_prefix:
            t_vision = 0.0
            t1 = time.perf_counter()
            t_prefix = time.perf_counter() - t1
        else:
            vision_tokens = self.run_vision(images_hwc)
            t_vision = time.perf_counter() - t0

            t1 = time.perf_counter()
            seq_len = _CFG["model"]["prefill_max_seq_len"]
            valid_len = self.embed_and_concat_prefix(prompt_tokens, vision_tokens, seq_len=seq_len)
            prog_addr = self._compile_and_run(lambda: self.compile_prefix(seq_len, valid_len), label="prefix")
            t_prefix = time.perf_counter() - t1

            if getattr(self, "PREFIX_SNAPSHOTS", False):
                self._prefix_layer0_op_snr_report(prompt_tokens, vision_tokens, valid_len)

            if dump_prefix_path is not None:
                self.dump_prefix_kv(dump_prefix_path)

        if sanity_check:
            print(f"timing: vision={t_vision:.2f}s prefix={t_prefix:.2f}s (sanity-check mode, "
                  f"skipping action-expert/denoise)")
            self.sanity_matmul_check()
            return None

        t2 = time.perf_counter()
        self.tensor_init_action_expert()
        S, AD = self.AE_ACTION_HORIZON_PADDED, self.AE_XT_WIDTH  # x_t buffer is 64-wide
        if noise32 is None:
            # Padding rows/cols must NOT be exact zero: rms_norm_core has no
            # epsilon, so an all-zero row -> rsqrt(0)=inf -> NaN, which then
            # contaminates every real row too since self-attention mixes all
            # S=64 rows together (same bug class fixed in embed_and_concat_prefix).
            noise32 = np.full((S, AD), 1e-6, dtype=np.float32)
            noise32[:10, :7] = np.random.RandomState(0).randn(10, 7)
        self.dma_write(DMA_DEVICE_H2C, self.AE_XT_DRAM,
                        torch.from_numpy(noise32).to(torch.bfloat16), S * AD * 2)
        if verify_prefix_kv and not skip_prefix:
            # Re-read LAYER0_K_DRAM/LAYER0_V_DRAM right here (after
            # tensor_init_action_expert's own DRAM allocations, right before
            # compile_denoise_loop's capture starts) and diff against the
            # snapshot dump_prefix_kv took right after compile_prefix -- tests
            # whether the prefix K/V cache is still intact at this exact point
            # in the SAME run that reliably NaNs, vs. the --debug run which
            # only ever re-loads a cache that was never live through this
            # sequence of allocations/executions to begin with.
            self.verify_prefix_kv("right before compile_denoise_loop")
        # compile_denoise_loop is statically unrolled (10 steps x 18 layers = 180
        # static layer bodies, 1440 flash-attention jump sites) -- same proven
        # pattern as compile_prefix/compile_encoder. A loop_start/loop_end runtime
        # loop was tried (single small compiled body, runtime trip count) but hung
        # on any real repeat even after fixing a genuine found bug (missing 64B
        # alignment before the backward-branch jump target); that combination
        # (loop_start/loop_end wrapping an internal shared-subroutine jump-and-
        # return) isn't proven anywhere else in this codebase, so static unrolling
        # was reverted to. Confirmed clean: full run completed in 123.9s (close to
        # the ~120-150s predicted from a standalone single-step measurement).
        self._compile_and_run(self.compile_denoise_loop, label="denoise_loop", timeout=300.0)
        t_denoise = time.perf_counter() - t2

        # DRAM-overlap check: adding PREFIX_LAYER_SNAPSHOT_DRAM/PREFIX_L0_SNAPSHOT_DRAM
        # shifted the tensor-DRAM allocator base by ~96MB (0xEE398AC0 -> 0xF3F68AC0)
        # vs the last known-clean run -- this codebase has hit exactly this bug class
        # before (see LocateAnything's decode-NaN/DRAM-overlap postmortem), so check
        # ae_k_combined (seeded by compile_denoise_loop's own captured copy) directly
        # before trusting the final action output.
        P_chk, D_chk = self.AE_PREFIX_SEQ_LEN, self.HEAD_DIM
        Tkv = self.AE_TKV
        for layer in (0, self.AE_LAYERS - 1):
            # Check ae_k_combined (full buffer: prefix + suffix regions)
            buf_k = bytearray(Tkv * D_chk * 2)
            self.dma_read(DMA_DEVICE_C2H, self.ae_k_combined[layer], buf_k, len(buf_k))
            k_full = torch.frombuffer(bytes(buf_k), dtype=torch.bfloat16).reshape(Tkv, D_chk).float()
            k_prefix = k_full[:P_chk]
            k_suffix = k_full[P_chk:]
            print(f"  [ae_kv_check] layer{layer} ae_k_combined prefix[0:{P_chk}]: "
                  f"nan={torch.isnan(k_prefix).sum().item()} inf={torch.isinf(k_prefix).sum().item()} "
                  f"min={k_prefix.min():.4f} max={k_prefix.max():.4f}")
            print(f"  [ae_kv_check] layer{layer} ae_k_combined suffix[{P_chk}:{Tkv}]: "
                  f"nan={torch.isnan(k_suffix).sum().item()} inf={torch.isinf(k_suffix).sum().item()} "
                  f"min={k_suffix.min():.4f} max={k_suffix.max():.4f}")

            # Check ae_v_combined (full buffer: prefix + suffix regions)
            buf_v = bytearray(Tkv * D_chk * 2)
            self.dma_read(DMA_DEVICE_C2H, self.ae_v_combined[layer], buf_v, len(buf_v))
            v_full = torch.frombuffer(bytes(buf_v), dtype=torch.bfloat16).reshape(Tkv, D_chk).float()
            v_prefix = v_full[:P_chk]
            v_suffix = v_full[P_chk:]
            print(f"  [ae_kv_check] layer{layer} ae_v_combined prefix[0:{P_chk}]: "
                  f"nan={torch.isnan(v_prefix).sum().item()} inf={torch.isinf(v_prefix).sum().item()} "
                  f"min={v_prefix.min():.4f} max={v_prefix.max():.4f}")
            print(f"  [ae_kv_check] layer{layer} ae_v_combined suffix[{P_chk}:{Tkv}]: "
                  f"nan={torch.isnan(v_suffix).sum().item()} inf={torch.isinf(v_suffix).sum().item()} "
                  f"min={v_suffix.min():.4f} max={v_suffix.max():.4f}")

        buf = bytearray(S * AD * 2)
        self.dma_read(DMA_DEVICE_C2H, self.AE_XT_DRAM, buf, len(buf))
        out = torch.frombuffer(bytes(buf), dtype=torch.bfloat16).reshape(S, AD).float().numpy()
        actions = out[:10, :7]

        print(f"timing: vision={t_vision:.2f}s prefix={t_prefix:.2f}s denoise={t_denoise:.2f}s "
              f"total={t_vision+t_prefix+t_denoise:.2f}s")
        return actions

    # XDMA driver has a per-os.write() transfer size limit (~16-64MB, matching
    # parakeet_test.py's/mobilenetv2_224_test.py's documented workaround). A
    # single-shot dma_write of a large program blob (pi05's compiled prefix
    # program is ~684MB) fails deterministically with `[Errno 512]` after
    # transferring a partial chunk (~57MB observed) -- this was misread at
    # first as an address-boundary bug (it correlated with >4GB addresses by
    # coincidence: the small 745KB vision program always fit under the limit,
    # while the ~684MB prefix program never does, regardless of address).
    # Real fix: chunk large writes, exactly like parakeet/mobilenetv2 already do.
    DMA_CHUNK_BYTES = 1 * 1024 * 1024  # 1 MB per chunk

    def _dma_write_retry(self, device, address, buffer, size, attempts=5):
        """Chunked + retried DMA write. A failed/incomplete program-blob write
        here means start_execute_from_dram runs stale/garbage DRAM content --
        this bit us for real (denoise-loop program silently didn't get written,
        producing garbage action output) so this is NOT optional."""
        data = bytes(buffer[:size]) if isinstance(buffer, (bytes, bytearray)) else buffer
        if size <= self.DMA_CHUNK_BYTES:
            for i in range(attempts):
                n = self.dma_write(device, address, data, size)
                if n == size:
                    return n
                print(f"  [dma_write_retry] attempt {i+1}/{attempts} failed (wrote {n}, wanted {size}), retrying...")
            raise RuntimeError(f"dma_write to 0x{address:X} failed after {attempts} attempts")

        offset = 0
        while offset < size:
            chunk_size = min(self.DMA_CHUNK_BYTES, size - offset)
            chunk = data[offset:offset + chunk_size] if isinstance(data, (bytes, bytearray)) \
                else data.flatten()[offset:offset + chunk_size]
            self._dma_write_retry(device, address + offset, chunk, chunk_size, attempts=attempts)
            offset += chunk_size
        return size

    def _wait_with_heartbeat(self, label, timeout=180.0, heartbeat_every=10.0):
        """wait_queue wrapper that prints elapsed seconds every heartbeat_every
        seconds on a background thread, so a real hang (dead silent, no CPU
        activity) is visually distinguishable from a slow-but-alive execute --
        we were guessing this blind before and burning time on ambiguous kills.

        CRITICAL: user_dma_core.wait_queue() does NOT raise on timeout -- it
        just prints "Error: wait_queue() timed out..." and returns normally,
        so callers silently proceed as if the FPGA finished. This wrapper
        checks is_queue_busy() itself after wait_queue returns and raises for
        real if the hardware is still busy, so a genuine hang surfaces as a
        hard failure instead of silently corrupting every downstream stage
        (this bit us for real: prefix's execution may never have actually
        finished before we compiled and ran the denoise loop on top of it)."""
        import threading
        t0 = time.perf_counter()
        stop = threading.Event()
        def _hb():
            while not stop.wait(1.0):
                _original_print(f"  [{label}] running... {time.perf_counter()-t0:.0f}s", end="\r", flush=True)
        hb_th = threading.Thread(target=_hb, daemon=True)
        hb_th.start()
        try:
            self.wait_queue(timeout)
        finally:
            stop.set()
            hb_th.join(timeout=1.0)
        if self.is_queue_busy():
            _original_print()
            raise RuntimeError(
                f"[{label}] FPGA queue still busy after {timeout:.0f}s timeout -- "
                f"real hang, not a silent success. wait_queue() does not raise on "
                f"its own; this check exists specifically to catch that.")
        _original_print(f"  [{label}] done in {time.perf_counter()-t0:.1f}s" + " " * 20)

    def _compile_and_run(self, compile_fn, label="compile_and_run", timeout=250.0):
        """compile_fn must itself do start_capture/.../stop_capture + DMA the
        program bytes and return the program addr (compile_prefix/compile_denoise_loop
        don't currently do the capture/dma/execute bookkeeping compile_encoder does --
        wrap them the same way here). Compile-phase prints (per-op FLOPs/URAM
        dumps from user_dma_core) are noisy and drown the timing/NaN signal we
        actually care about, so they're silenced the same way qwen3_4b/
        locateanything_3b do it (global _SILENT_MODE flag over builtins.print)."""
        global _SILENT_MODE
        _original_print(f"  [{label}] compiling...", end="\r", flush=True)
        t_compile0 = time.perf_counter()
        _SILENT_MODE = True
        prog_len = 0
        try:
            self.start_capture()
            prog_addr = compile_fn()
            # compile_prefix/compile_denoise_loop don't call stop_capture/emit themselves
            # (only compile_encoder does) -- if compile_fn already stopped capture and
            # returned an addr (compile_encoder-style), reuse it; else emit now.
            if self.capture_buffer:
                all_bytes = bytearray()
                for inst in self.capture_buffer:
                    all_bytes.extend(inst.get_bytes())
                prog_addr = self.get_program_dram_addr()
                prog_len = len(all_bytes)
                self._dma_write_retry(DMA_DEVICE_H2C, prog_addr, all_bytes, prog_len)
                self.allocate_program_dram(prog_len)
                self.clear_capture_buffer()
            self.stop_capture()
        finally:
            _SILENT_MODE = False
        prog_end = prog_addr + prog_len
        tensor_end = self.get_tensor_dram_addr()
        FOURGB = 0x100000000
        prog_base = getattr(self, "_program_dram_base", 0xF8000000)
        _original_print(
            f"  [{label}] ADDR: prog=[0x{prog_addr:X}..0x{prog_end:X}] len={prog_end-prog_addr}B "
            f"tensor_end=0x{tensor_end:X} prog_base=0x{prog_base:X} 4GB=0x{FOURGB:X} | "
            f"prog_crosses_4GB={prog_end > FOURGB} tensor_hits_prog={tensor_end > prog_base}")
        _original_print(f"  [{label}] compiled in {time.perf_counter()-t_compile0:.1f}s" + " " * 20)
        self.start_execute_from_dram(prog_addr)
        self._wait_with_heartbeat(label, timeout=timeout)
        return prog_addr


def main():
    import argparse
    ap = argparse.ArgumentParser()
    ap.add_argument("--debug", action="store_true",
                     help="skip vision+prefix (~185s) and reload the last-dumped prefix K/V "
                          "cache from PREFIX_KV_DUMP_PATH instead -- for fast denoise-loop-only "
                          "iteration. Requires a prior non-debug run (which auto-dumps).")
    ap.add_argument("--steps", type=int, default=None,
                     help="override AE_NUM_DENOISE_STEPS (e.g. --steps 1 to stop after the first "
                          "Euler step, since step0 already NaNs -- no point paying for all 10).")
    ap.add_argument("--verify-prefix-tensor", action="store_true",
                     help="in a full (non-debug) run, re-read the prefix K/V cache right before "
                          "compile_denoise_loop starts and diff it byte-for-byte against the "
                          "snapshot taken right after compile_prefix finished -- proves whether "
                          "the SAME K/V tensor that fed a clean --debug denoise run is still "
                          "intact at the point the full run's denoise starts, or gets clobbered "
                          "somewhere in between.")
    ap.add_argument("--sanity-check", action="store_true",
                     help="isolation test: run vision + prefix for real, then instead of the full "
                          "denoise loop, run a small basic bf16 matmul (no IF4 quant, no PBI, no "
                          "special registers) and diff it against a CPU reference. Tests raw "
                          "post-vision+prefix hardware health with the simplest possible op, "
                          "independent of anything denoise-loop-specific.")
    ap.add_argument("--verify-denoise", action="store_true",
                     help="after the full FPGA run, run pi05_torch_ref.run_pi05 on CPU with the "
                          "SAME quant (IF4, matching lm_quant/vision_quant=q4_64), SAME images, "
                          "SAME prompt tokens, SAME state, and the SAME RandomState(0) noise -- so "
                          "the only variable is HW-vs-CPU execution -- and report per-dim / "
                          "per-timestep / overall SNR of the (10,7) action output.")
    ap.add_argument("--probe-step0", action="store_true",
                     help="snapshot step-0 action-expert intermediates and diff each against the "
                          "torch reference (fed the FPGA's own K/V) to localize which op first "
                          "diverges. Works with --debug for a fast ~75s iteration loop.")
    ap.add_argument("--ref-device", default="auto", choices=["auto", "cuda", "cpu"],
                     help="device for the --verify-denoise reference run. 'auto' (default) "
                          "uses cuda if available (7Hz path, ~100x faster than CPU bf16), "
                          "else cpu.")
    args, _ = ap.parse_known_args()

    PREFIX_KV_DUMP_PATH = os.path.join(os.path.dirname(__file__), "debug_prefix_kv.npz")

    if args.steps is not None:
        Pi05Libero_UnifiedEngine.AE_NUM_DENOISE_STEPS = args.steps
        print(f"[main] AE_NUM_DENOISE_STEPS overridden to {args.steps}")

    if args.probe_step0:
        Pi05Libero_UnifiedEngine.DENOISE_STEP0_PROBE = True
        print("[main] DENOISE_STEP0_PROBE enabled -- will snapshot + diff step-0 intermediates")

    ue = Pi05Libero_UnifiedEngine()
    init_hang_prevention(ue)
    ue.weight_init()
    ue.tensor_init(_CFG["defaults"].get("max_seq", 512))

    # Full end-to-end: vision -> prefix -> action-expert denoise loop.
    # Vision: confirmed hang-free (all 3 slots, 432 head-jumps).
    # Prefix: NaN (padding-row epsilon) and hang (_dram_split_copy strided DMA)
    # bugs fixed -- see embed_and_concat_prefix's padding comment and
    # _weight_init_lm_prefix's FF_HALF-split comment -- confirmed clean for the
    # FULL 18 layers with real vision data (182s).
    # Denoise loop: confirmed clean standalone with a placeholder (zero-filled)
    # K/V cache (123.9s, statically unrolled -- see compile_denoise_loop's
    # docstring for why it's not a loop_start/loop_end runtime loop). This is
    # the first time all three stages run back-to-back together with the REAL
    # prefix K/V cache feeding the action-expert -- genuinely uncharted, so
    # treat any failure here as new territory, not a regression.
    if args.debug:
        # Fast path: skip vision+prefix (~185s), reload the prefix K/V cache
        # dumped by a prior non-debug run. images/prompt_tokens are unused.
        assert os.path.exists(PREFIX_KV_DUMP_PATH), (
            f"--debug requires a prior non-debug run to have dumped {PREFIX_KV_DUMP_PATH} first "
            f"(run without --debug once, then rerun with --debug for fast iteration).")
        ue.load_prefix_kv(PREFIX_KV_DUMP_PATH)
        actions = ue.run_inference(None, None, skip_prefix=True)
    else:
        sample_dir = Path.home() / "apex-compute-ML" / "simple-llm" / "src" / "models" / "pi0_5" / "sample_data"
        img = np.load(sample_dir / "sample_0_image.npy").astype(np.float32) / 127.5 - 1.0
        wrist = np.load(sample_dir / "sample_0_wrist_image.npy").astype(np.float32) / 127.5 - 1.0
        pad = np.zeros_like(img)
        import torch.nn.functional as _F
        def _resize(a):
            t = torch.from_numpy(a).permute(2, 0, 1).unsqueeze(0).float()
            t = _F.interpolate(t, size=(224, 224), mode="bilinear", align_corners=False)
            return t.squeeze(0).permute(1, 2, 0).numpy()
        images = [_resize(img), _resize(wrist), _resize(pad)]

        # Real tokenization (matches openpi's PaligemmaTokenizer.tokenize, Pi05
        # format -- state discretized into the language prompt text, NOT fed as a
        # separate continuous input): "Task: {prompt}, State: {digitized state};\nAction: "
        # tokenized with sentencepiece + BOS. Was a random-token placeholder before,
        # which produced garbage language conditioning and a wildly out-of-range
        # (+-2.4) output vs the real policy's near-[-1,1] result.
        import sentencepiece
        norm_stats = json.loads(
            (Path.home() / ".cache" / "openpi" / "openpi-assets" / "checkpoints" / "pi05_libero"
             / "assets" / "physical-intelligence" / "libero" / "norm_stats.json").read_text()
        )["norm_stats"]
        meta = json.loads((sample_dir / "meta.json").read_text())
        state = np.array(meta["state_example"], dtype=np.float32)
        state_q01 = np.array(norm_stats["state"]["q01"], dtype=np.float32)
        state_q99 = np.array(norm_stats["state"]["q99"], dtype=np.float32)
        state_norm = np.clip((state - state_q01) / (state_q99 - state_q01 + 1e-6) * 2.0 - 1.0, -1.0, 1.0)
        digitized_state = np.digitize(state_norm, bins=np.linspace(-1, 1, 257)[:-1]) - 1
        state_str = " ".join(map(str, digitized_state))
        full_prompt = f"Task: {_CFG['defaults'].get('prompt', 'pick up the object')}, State: {state_str};\nAction: "

        sp = sentencepiece.SentencePieceProcessor(
            model_file=str(Path.home() / ".cache" / "openpi" / "big_vision" / "paligemma_tokenizer.model"))
        prompt_tokens = np.array(sp.encode(full_prompt, add_bos=True), dtype=np.int64)

        actions = ue.run_inference(
            images, prompt_tokens, dump_prefix_path=PREFIX_KV_DUMP_PATH,
            verify_prefix_kv=args.verify_prefix_tensor, sanity_check=args.sanity_check)

        if args.sanity_check:
            return

    if args.probe_step0:
        ue.verify_denoise_step0(PREFIX_KV_DUMP_PATH)

    np.set_printoptions(precision=4, suppress=True)
    print("action_chunk shape (raw model output):", actions.shape)
    print(actions)
    print(f"nan={np.isnan(actions).any()} inf={np.isinf(actions).any()} "
          f"min={actions.min():.4f} max={actions.max():.4f}")

    if not args.debug:
        # Unnormalize to real action space (matches openpi's Unnormalize transform:
        # (x+1)/2*(q99-q01)+q01) using the same actions norm_stats, so this is
        # directly comparable to run_pi05.py's printed action_chunk. Skipped in
        # --debug mode since norm_stats/tokenization aren't loaded there.
        act_q01 = np.array(norm_stats["actions"]["q01"], dtype=np.float32)
        act_q99 = np.array(norm_stats["actions"]["q99"], dtype=np.float32)
        actions_unnorm = (actions + 1.0) / 2.0 * (act_q99 - act_q01 + 1e-6) + act_q01
        print("action_chunk (unnormalized, comparable to run_pi05.py):")
        print(actions_unnorm)

    if args.verify_denoise and not args.debug:
        # CPU IF4 reference, matched apples-to-apples: same quant our model uses
        # (q4_64 == if4), same images/prompt/state, and CRUCIALLY the same
        # RandomState(0) noise the FPGA denoise seeds (run_inference uses
        # noise32[:10,:7] = RandomState(0).randn(10,7); the reference's own
        # main() uses torch.manual_seed(0) -- a DIFFERENT RNG -- so we must
        # feed the exact numpy array here, not let it reseed). Isolates pure
        # HW-vs-CPU execution error (no noise-seed, no quant-policy confound).
        import pi05_torch_ref as _ref
        ref_device = args.ref_device
        if ref_device == "auto":
            ref_device = "cuda" if torch.cuda.is_available() else "cpu"
        print(f"[verify-denoise] running IF4 reference (pi05_torch_ref.run_pi05) on "
              f"{ref_device}... vision+prefix+denoise"
              + (" on GPU (fast)" if ref_device == "cuda"
                 else " on CPU (bf16, slow -- pass --ref-device cuda if you have a GPU)"))
        W = _ref.Weights(device=ref_device, dtype=torch.bfloat16, quant="if4")
        ref_images = torch.stack([torch.from_numpy(im).to(torch.bfloat16) for im in images], dim=0).to(ref_device)
        ref_prompt = torch.from_numpy(prompt_tokens).long().unsqueeze(0).to(ref_device)
        ref_state = torch.tensor([meta["state_example"]], dtype=torch.float32).to(ref_device)
        noise7 = np.random.RandomState(0).randn(10, 7).astype(np.float32)  # SAME as run_inference
        noise32 = torch.zeros(1, 10, 32, dtype=torch.float32)
        noise32[..., :7] = torch.from_numpy(noise7)
        noise32 = noise32.to(ref_device)
        ref_actions, ref_kv = _ref.run_pi05(ref_images, ref_prompt, ref_state, W,
                                            noise=noise32, return_kv=True)
        ref_actions = ref_actions[..., :7]
        ref_np = ref_actions.squeeze(0).float().cpu().numpy()

        # --- Prefix K/V comparison: FPGA dumped cache vs reference cache ---
        # Splits the failure: if prefix K/V matches, the bug is in the action
        # head; if it diverges, the break is at/inside prefix.
        try:
            kv_path = PREFIX_KV_DUMP_PATH
            npz = np.load(kv_path)
            NL, D = ue.NUM_LAYERS, ue.HEAD_DIM
            vlen = int(npz["prefix_valid_len"])
            # per-layer row stride is the ALLOCATED seq (max_seq_len, padded),
            # not PREFIX_SEQ_LEN -- derive it from the buffer size so we don't
            # assume. total_elems = NL * stride_rows * D.
            stride_rows = npz["k"].size // (NL * D)
            fpga_k = torch.frombuffer(npz["k"].tobytes(), dtype=torch.bfloat16).float().reshape(NL, stride_rows, D)
            fpga_v = torch.frombuffer(npz["v"].tobytes(), dtype=torch.bfloat16).float().reshape(NL, stride_rows, D)
            ref_k_list, ref_v_list = ref_kv  # each: list of 18 (b,P,1,256)
            print(f"=== Prefix K/V SNR: FPGA cache vs CPU-IF4 reference (valid_len={vlen}) ===")
            def _snr(a, b):
                return 20 * torch.log10(b.norm() / (a - b).norm().clamp_min(1e-12)).item()
            for L in range(NL):
                rk = ref_k_list[L].squeeze(0).squeeze(1).float().cpu()  # (P,256)
                rv = ref_v_list[L].squeeze(0).squeeze(1).float().cpu()
                P = min(rk.shape[0], vlen)
                fk = fpga_k[L, :P]
                fv = fpga_v[L, :P]
                print(f"  layer{L:2d}: K_SNR={_snr(fk, rk[:P]):6.2f}dB  V_SNR={_snr(fv, rv[:P]):6.2f}dB")
        except Exception as e:
            print(f"[prefix-kv-compare] skipped: {e}")

        hw = torch.from_numpy(actions).float()      # (10,7) FPGA
        cpu = torch.from_numpy(ref_np).float()      # (10,7) CPU IF4
        def _snr(a, b):
            return 20 * torch.log10(b.norm() / (a - b).norm().clamp_min(1e-12)).item()
        print("=== FPGA vs CPU-IF4 denoise SNR (matched noise/inputs) ===")
        print(f"  overall: SNR={_snr(hw, cpu):.2f}dB  MSE={((hw-cpu)**2).mean().item():.6f}")
        for d in range(7):
            print(f"  dim{d}: SNR={_snr(hw[:, d], cpu[:, d]):.2f}dB  "
                  f"hw[{hw[:,d].min():.3f},{hw[:,d].max():.3f}] cpu[{cpu[:,d].min():.3f},{cpu[:,d].max():.3f}]")
        for tstep in range(10):
            print(f"  step{tstep}: SNR={_snr(hw[tstep], cpu[tstep]):.2f}dB")
        print("CPU-IF4 reference action_chunk (10,7):")
        print(ref_np)

    ue.probe_nan_report()


if __name__ == "__main__":
    main()
